import React, { useState, useEffect } from 'react';
import { ShoppingBag, User, Search, Menu, X } from 'lucide-react';

interface HeaderProps {
  cartCount: number;
  onCartClick: () => void;
  onUserClick: () => void;
  onHomeClick: () => void;
}

const Header: React.FC<HeaderProps> = ({ cartCount, onCartClick, onUserClick, onHomeClick }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <header 
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
        isScrolled ? 'bg-white shadow-sm py-3' : 'bg-transparent py-6'
      }`}
    >
      <div className="container mx-auto px-6 flex items-center justify-between">
        {/* Mobile Menu Toggle */}
        <button 
          className="lg:hidden p-2 -ml-2"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>

        {/* Logo */}
        <button 
          onClick={onHomeClick}
          className="text-2xl font-medium tracking-widest serif text-gray-900 lg:absolute lg:left-1/2 lg:-translate-x-1/2"
        >
          VITALITY <span className="font-light text-sm tracking-[0.2em] ml-1 block lg:inline lg:ml-2">NUTRACEUTICALS</span>
        </button>

        {/* Desktop Nav */}
        <nav className="hidden lg:flex items-center space-x-10 text-[11px] font-medium tracking-[0.2em] uppercase">
          <a href="#" className="hover:text-gray-500 transition-colors">Best Sellers</a>
          <a href="#" className="hover:text-gray-500 transition-colors">Skincare</a>
          <a href="#" className="hover:text-gray-500 transition-colors">Wellness</a>
          <a href="#" className="hover:text-gray-500 transition-colors">Our Story</a>
        </nav>

        {/* Icons */}
        <div className="flex items-center space-x-4 lg:space-x-6">
          <button className="p-2 hover:opacity-60 transition-opacity hidden md:block">
            <Search className="w-5 h-5 font-light" />
          </button>
          <button 
            onClick={onUserClick}
            className="p-2 hover:opacity-60 transition-opacity"
          >
            <User className="w-5 h-5 font-light" />
          </button>
          <button 
            onClick={onCartClick}
            className="p-2 hover:opacity-60 transition-opacity relative"
          >
            <ShoppingBag className="w-5 h-5 font-light" />
            {cartCount > 0 && (
              <span className="absolute top-0 right-0 bg-[#344e41] text-white text-[9px] w-4 h-4 rounded-full flex items-center justify-center translate-x-1/4 -translate-y-1/4">
                {cartCount}
              </span>
            )}
          </button>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 top-[72px] bg-white z-40 fade-in px-8 py-12 flex flex-col space-y-8 text-sm tracking-[0.1em] uppercase">
          <a href="#" className="border-b border-gray-100 pb-4">Best Sellers</a>
          <a href="#" className="border-b border-gray-100 pb-4">Skincare</a>
          <a href="#" className="border-b border-gray-100 pb-4">Wellness</a>
          <a href="#" className="border-b border-gray-100 pb-4">Our Story</a>
        </div>
      )}
    </header>
  );
};

export default Header;

import React from 'react';
import { Product } from '../types';

interface ProductCardProps {
  product: Product;
  onAddToCart: (product: Product) => void;
  onViewDetail: (product: Product) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onAddToCart, onViewDetail }) => {
  return (
    <div className="group cursor-pointer flex flex-col items-center">
      <div 
        className="relative overflow-hidden mb-6 w-full aspect-[4/5] bg-[#f9f9f9]"
        onClick={() => onViewDetail(product)}
      >
        <img 
          src={product.image_url} 
          alt={product.name} 
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
        />

        {/* Quick Add Overlay */}
        <div className="absolute bottom-0 left-0 right-0 bg-white/90 backdrop-blur-sm py-4 translate-y-full transition-transform duration-500 group-hover:translate-y-0 flex justify-center">
          <button 
            onClick={(e) => {
              e.stopPropagation();
              onAddToCart(product);
            }}
            className="text-[10px] uppercase tracking-[0.2em] font-medium hover:text-gray-500 transition-colors"
          >
            + Add to Bag
          </button>
        </div>
      </div>

      <div className="text-center space-y-2" onClick={() => onViewDetail(product)}>
        <span className="text-[10px] uppercase tracking-[0.2em] text-gray-400 font-medium">
          {product.category}
        </span>
        <h3 className="text-lg serif text-gray-800 tracking-wide group-hover:text-gray-500 transition-colors">
          {product.name}
        </h3>
        <div className="flex items-center justify-center space-x-3">
          <span className="text-sm font-medium tracking-wider">
            NT$ {product.price.toLocaleString()}
          </span>
          {product.original_price > product.price && (
            <span className="text-xs text-gray-400 line-through tracking-wider">
              NT$ {product.original_price.toLocaleString()}
            </span>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import ProductCard from './components/ProductCard';
import { Product, CartItem, Member } from './types';
import { MOCK_PRODUCTS } from './data/mockData';
import { X, ChevronRight, ShoppingBag, ArrowLeft, CheckCircle } from 'lucide-react';

type View = 'Home' | 'ProductDetail' | 'Cart' | 'Login' | 'Account';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('Home');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<Member | null>(null);

  // Load cart from localStorage
  useEffect(() => {
    const savedCart = localStorage.getItem('vnutra_cart');
    if (savedCart) {
      try {
        setCart(JSON.parse(savedCart));
      } catch (e) {
        console.error('Failed to parse cart');
      }
    }
  }, []);

  // Save cart to localStorage
  useEffect(() => {
    localStorage.setItem('vnutra_cart', JSON.stringify(cart));
  }, [cart]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product_id === product.product_id);
      if (existing) {
        return prev.map(item => 
          item.product_id === product.product_id 
            ? { ...item, quantity: item.quantity + 1 } 
            : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.product_id !== productId));
  };

  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.product_id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen">
      <Header 
        cartCount={cartCount} 
        onCartClick={() => setIsCartOpen(true)}
        onUserClick={() => setCurrentView('Login')}
        onHomeClick={() => {
          setCurrentView('Home');
          window.scrollTo({ top: 0, behavior: 'smooth' });
        }}
      />

      <main className="pt-[72px]">
        {currentView === 'Home' && (
          <div className="fade-in">
            <Hero />

            <section className="py-24 bg-white">
              <div className="container mx-auto px-6">
                <div className="flex flex-col md:flex-row md:items-end justify-between mb-16 space-y-4 md:space-y-0">
                  <div>
                    <span className="text-[10px] uppercase tracking-[0.4em] text-gray-400 mb-2 block font-medium">Exquisite Formulation</span>
                    <h2 className="text-4xl md:text-5xl serif tracking-wide">Featured Collections</h2>
                  </div>
                  <button className="text-[10px] uppercase tracking-[0.3em] font-medium border-b border-gray-900 pb-1 hover:text-gray-400 hover:border-gray-400 transition-all">
                    View All Products
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-x-8 gap-y-16">
                  {MOCK_PRODUCTS.map(product => (
                    <ProductCard 
                      key={product.product_id} 
                      product={product} 
                      onAddToCart={addToCart}
                      onViewDetail={(p) => {
                        setSelectedProduct(p);
                        setCurrentView('ProductDetail');
                        window.scrollTo(0, 0);
                      }}
                    />
                  ))}
                </div>
              </div>
            </section>

            {/* Aesthetic Storytelling Section */}
            <section className="py-32 bg-[#fafafa]">
              <div className="container mx-auto px-6 grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
                <div className="relative aspect-[4/5] overflow-hidden">
                  <img 
                    src="https://images.unsplash.com/photo-1556228720-195a672e8a03?auto=format&fit=crop&q=80&w=1200" 
                    className="w-full h-full object-cover" 
                    alt="Process"
                  />
                </div>
                <div className="lg:pl-12 space-y-8">
                  <span className="text-[10px] uppercase tracking-[0.4em] text-gray-400 block font-medium">The Science of Essence</span>
                  <h2 className="text-5xl serif leading-tight">Meticulously Crafted <br /> For Absolute Potency</h2>
                  <p className="text-gray-600 font-light leading-loose text-lg">
                    Every ingredient is selected through rigorous clinical review, ensuring that our formulas not only meet but exceed the gold standards of nutraceutical excellence. We believe in transparency, purity, and the transformative power of nature refined by science.
                  </p>
                  <button className="px-10 py-4 border border-gray-900 text-[10px] uppercase tracking-[0.3em] hover:bg-gray-900 hover:text-white transition-all duration-500">
                    Explore Our Heritage
                  </button>
                </div>
              </div>
            </section>
          </div>
        )}

        {currentView === 'ProductDetail' && selectedProduct && (
          <div className="fade-in container mx-auto px-6 py-16">
            <button 
              onClick={() => setCurrentView('Home')}
              className="flex items-center space-x-2 text-[10px] uppercase tracking-[0.2em] text-gray-400 hover:text-gray-900 mb-12"
            >
              <ArrowLeft className="w-4 h-4" />
              <span>Back to Collections</span>
            </button>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-16">
              <div className="aspect-square bg-gray-50 overflow-hidden">
                <img 
                  src={selectedProduct.image_url} 
                  className="w-full h-full object-cover" 
                  alt={selectedProduct.name} 
                />
              </div>
              <div className="flex flex-col justify-center">
                <span className="text-[10px] uppercase tracking-[0.4em] text-gray-400 font-medium mb-4 block">
                  {selectedProduct.category}
                </span>
                <h1 className="text-5xl serif mb-6 tracking-wide">{selectedProduct.name}</h1>
                <div className="flex items-baseline space-x-4 mb-8">
                  <span className="text-2xl font-light tracking-widest">NT$ {selectedProduct.price.toLocaleString()}</span>
                  {selectedProduct.original_price > selectedProduct.price && (
                    <span className="text-lg text-gray-300 line-through">NT$ {selectedProduct.original_price.toLocaleString()}</span>
                  )}
                </div>

                <p className="text-gray-600 leading-relaxed font-light mb-12 text-lg">
                  {selectedProduct.description}
                </p>

                <div className="border-t border-b border-gray-100 py-8 mb-12 space-y-4">
                  <div className="flex items-center justify-between text-xs tracking-[0.1em]">
                    <span className="font-medium">SPECIFICATION</span>
                    <span className="text-gray-500 uppercase">{selectedProduct.spec}</span>
                  </div>
                  <div className="flex items-center justify-between text-xs tracking-[0.1em]">
                    <span className="font-medium">AVAILABILITY</span>
                    <span className={selectedProduct.stock > 0 ? 'text-green-600' : 'text-red-600'}>
                      {selectedProduct.stock > 0 ? `In Stock (${selectedProduct.stock})` : 'Sold Out'}
                    </span>
                  </div>
                </div>

                <div className="flex space-x-4">
                  <button 
                    onClick={() => addToCart(selectedProduct)}
                    disabled={selectedProduct.stock <= 0}
                    className="flex-1 bg-gray-900 text-white py-5 text-[10px] uppercase tracking-[0.3em] hover:bg-gray-800 transition-colors disabled:opacity-50"
                  >
                    Add to Shopping Bag
                  </button>
                </div>
              </div>
            </div>

            <div className="mt-32 border-t border-gray-100 pt-16 max-w-4xl mx-auto">
              <h3 className="text-2xl serif mb-8 text-center tracking-widest">DETAILS & USAGE</h3>
              <div className="prose prose-sm max-w-none text-gray-600 font-light leading-loose text-center">
                {selectedProduct.detail_content}
              </div>
            </div>
          </div>
        )}

        {currentView === 'Login' && (
          <div className="fade-in max-w-md mx-auto py-24 px-6 text-center">
            <h2 className="text-4xl serif mb-12 tracking-widest uppercase">Sign In</h2>
            <div className="space-y-6">
              <input 
                type="email" 
                placeholder="EMAIL ADDRESS" 
                className="w-full border-b border-gray-200 py-4 text-[10px] tracking-[0.2em] focus:border-gray-900 outline-none transition-colors uppercase"
              />
              <input 
                type="password" 
                placeholder="PASSWORD" 
                className="w-full border-b border-gray-200 py-4 text-[10px] tracking-[0.2em] focus:border-gray-900 outline-none transition-colors uppercase"
              />
              <button className="w-full bg-gray-900 text-white py-4 mt-8 text-[10px] uppercase tracking-[0.3em] hover:bg-gray-800 transition-all">
                Sign In
              </button>
              <div className="flex items-center justify-between text-[9px] tracking-[0.1em] text-gray-400 pt-4">
                <button className="hover:text-gray-900 transition-colors">FORGOT PASSWORD?</button>
                <button className="hover:text-gray-900 transition-colors">CREATE ACCOUNT</button>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-gray-100 py-24 mt-24">
        <div className="container mx-auto px-6">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12 mb-16">
            <div className="space-y-6">
              <h4 className="text-sm font-semibold tracking-[0.2em] uppercase">VITALITY NUTRACEUTICALS</h4>
              <p className="text-xs text-gray-400 font-light leading-loose tracking-widest uppercase">
                Redefining cellular longevity through the synthesis of rare natural ingredients and cutting-edge molecular science.
              </p>
            </div>
            <div className="space-y-6">
              <h4 className="text-sm font-semibold tracking-[0.2em] uppercase">Collections</h4>
              <ul className="text-xs text-gray-400 space-y-4 font-light tracking-[0.1em] uppercase">
                <li><a href="#" className="hover:text-gray-900 transition-colors">Best Sellers</a></li>
                <li><a href="#" className="hover:text-gray-900 transition-colors">Luminous Skincare</a></li>
                <li><a href="#" className="hover:text-gray-900 transition-colors">Wellness Essentials</a></li>
                <li><a href="#" className="hover:text-gray-900 transition-colors">Gift Sets</a></li>
              </ul>
            </div>
            <div className="space-y-6">
              <h4 className="text-sm font-semibold tracking-[0.2em] uppercase">Concierge</h4>
              <ul className="text-xs text-gray-400 space-y-4 font-light tracking-[0.1em] uppercase">
                <li><a href="#" className="hover:text-gray-900 transition-colors">Shipping & Returns</a></li>
                <li><a href="#" className="hover:text-gray-900 transition-colors">My Account</a></li>
                <li><a href="#" className="hover:text-gray-900 transition-colors">Track Your Order</a></li>
                <li><a href="#" className="hover:text-gray-900 transition-colors">Contact Us</a></li>
              </ul>
            </div>
            <div className="space-y-6">
              <h4 className="text-sm font-semibold tracking-[0.2em] uppercase">Newsletter</h4>
              <p className="text-[10px] text-gray-400 tracking-[0.1em] uppercase">Join for exclusive scientific insights and collection debuts.</p>
              <div className="flex border-b border-gray-900 pb-2">
                <input 
                  type="email" 
                  placeholder="EMAIL ADDRESS" 
                  className="bg-transparent text-[10px] tracking-[0.2em] outline-none flex-1 uppercase"
                />
                <button className="text-[10px] tracking-[0.2em] font-medium ml-4">SUBSCRIBE</button>
              </div>
            </div>
          </div>
          <div className="pt-8 border-t border-gray-50 flex flex-col md:flex-row justify-between items-center text-[10px] text-gray-400 tracking-[0.2em] uppercase space-y-4 md:space-y-0">
            <p>&copy; 2024 VITALITY NUTRACEUTICALS. ALL RIGHTS RESERVED.</p>
            <div className="flex space-x-8">
              <a href="#">Privacy Policy</a>
              <a href="#">Terms of Service</a>
            </div>
          </div>
        </div>
      </footer>

      {/* Cart Sidebar */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[100] overflow-hidden">
          <div className="absolute inset-0 bg-black/30 backdrop-blur-sm transition-opacity" onClick={() => setIsCartOpen(false)}></div>
          <div className="absolute top-0 right-0 bottom-0 w-full max-w-md bg-white shadow-2xl flex flex-col transform transition-transform duration-500 fade-in">
            <div className="px-8 py-10 flex items-center justify-between border-b border-gray-100">
              <h2 className="text-xl serif tracking-widest">SHOPPING BAG</h2>
              <button onClick={() => setIsCartOpen(false)} className="p-2 hover:opacity-50 transition-opacity">
                <X className="w-5 h-5 font-light" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto px-8 py-6 space-y-8">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center space-y-6">
                  <ShoppingBag className="w-12 h-12 text-gray-200 stroke-1" />
                  <p className="text-[10px] tracking-[0.2em] text-gray-400 uppercase">Your shopping bag is currently empty.</p>
                  <button 
                    onClick={() => setIsCartOpen(false)}
                    className="border border-gray-900 px-8 py-3 text-[10px] tracking-[0.2em] uppercase hover:bg-gray-900 hover:text-white transition-all"
                  >
                    Start Shopping
                  </button>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.product_id} className="flex space-x-6">
                    <div className="w-24 h-30 bg-gray-50 flex-shrink-0">
                      <img src={item.image_url} alt={item.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div>
                        <div className="flex justify-between items-start mb-1">
                          <h4 className="text-sm font-medium tracking-wide text-gray-800">{item.name}</h4>
                          <button onClick={() => removeFromCart(item.product_id)} className="text-gray-400 hover:text-red-500 p-1">
                            <X className="w-3 h-3" />
                          </button>
                        </div>
                        <span className="text-[9px] uppercase tracking-widest text-gray-400 font-medium">{item.category}</span>
                      </div>
                      <div className="flex items-center justify-between">
                        <div className="flex items-center border border-gray-100 px-2 py-1">
                          <button onClick={() => updateQuantity(item.product_id, -1)} className="p-1 hover:text-gray-500">-</button>
                          <span className="mx-3 text-xs">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.product_id, 1)} className="p-1 hover:text-gray-500">+</button>
                        </div>
                        <span className="text-xs font-medium tracking-widest">NT$ {(item.price * item.quantity).toLocaleString()}</span>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>

            {cart.length > 0 && (
              <div className="px-8 py-10 bg-[#fafafa] border-t border-gray-100">
                <div className="flex items-center justify-between mb-8">
                  <span className="text-[10px] tracking-[0.2em] font-medium uppercase">Total</span>
                  <span className="text-xl serif">NT$ {cartTotal.toLocaleString()}</span>
                </div>
                <button className="w-full bg-gray-900 text-white py-5 text-[10px] uppercase tracking-[0.3em] font-semibold hover:bg-gray-800 transition-all flex items-center justify-center space-x-3">
                  <span>Checkout Now</span>
                  <ChevronRight className="w-4 h-4" />
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

