  const [isCartOpen, setIsCartOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<Member | null>(null);

  // 獲取商品資料
  useEffect(() => {
    const fetchProducts = async () => {
      setIsLoading(true);
      try {
        // 如果還沒有填寫 URL，我們先用模擬數據撐場，讓開發者能看到樣子
        if (GAS_WEB_APP_URL.includes('YOUR_DEPLOYED_ID')) {
          console.warn('請將 Code.gs 部署後的網頁應用程式網址填入 GAS_WEB_APP_URL 中');
          // 延遲一下模擬載入感
          setTimeout(async () => {
            const { MOCK_PRODUCTS } = await import('./data/mockData');
            setProducts(MOCK_PRODUCTS);
            setIsLoading(false);
          }, 1000);
          return;
