/**
 * Google Apps Script 後端
 * 部署建議：每次修改後請務必「管理部署」並建立「新版本」，確保 URL 是最新的。
 */

const PRODUCT_SHEET_ID = '1AxzphT6sT3CYTwFDlhFftfZhLJh_OCfjCmxfF9I918U';

function doGet(e) {
  const action = e.parameter.action;

  // 設置 CORS 標頭的對應處理（GAS Web App 預設支援）
  try {
    if (action === 'getProducts') {
      return getProducts();
    }
    return createJsonResponse({ error: '未知的指令' });
  } catch (error) {
    return createJsonResponse({ error: '伺服器錯誤: ' + error.toString() });
  }
}

function getProducts() {
  const ss = SpreadsheetApp.openById(PRODUCT_SHEET_ID);
  const sheet = ss.getSheetByName('商品清單') || ss.getSheets()[0];
  const range = sheet.getDataRange();
  const data = range.getValues();

  if (data.length < 2) {
    return createJsonResponse([]);
  }

  // 處理標題：去除空格並轉為小寫（可選）以確保對應正確
  const headers = data[0].map(h => h.toString().trim());

  const products = data.slice(1).map((row, rowIndex) => {
    let obj = {};
    headers.forEach((header, i) => {
      let value = row[i];

      // 數字類型轉換
      if (['price', 'original_price', 'stock'].includes(header)) {
        value = (value === "" || isNaN(value)) ? 0 : Number(value);
      }

      // 確保字串類型不會是 null
      if (value === null || value === undefined) {
        value = "";
      }

      obj[header] = value;
    });
    return obj;
  }).filter(p => {
    // 狀態檢查：不分大小寫，且預設 Active 為回傳條件
    const statusStr = (p.status || "").toString().trim().toLowerCase();
    return statusStr === 'active';
  });

  return createJsonResponse(products);
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  return createJsonResponse({ message: 'Post method triggered' });
}

