 * 4. 誰可以存取：選擇「任何人」
 * 5. 每次更動代碼後，請務必點擊「管理部署」並建立「新版本」
 */

const PRODUCT_SHEET_ID = '1AxzphT6sT3CYTwFDlhFftfZhLJh_OCfjCmxfF9I918U';

function doGet(e) {
  const action = e.parameter.action;

  try {
    if (action === 'getProducts') {
      return getProducts();
    }
    return createJsonResponse({ error: '未知的請求指令' });
  } catch (error) {
    return createJsonResponse({ error: '伺服器端錯誤: ' + error.toString() });
  }
}

function getProducts() {
  const ss = SpreadsheetApp.openById(PRODUCT_SHEET_ID);
  const sheet = ss.getSheetByName('商品清單');

  if (!sheet) {
    return createJsonResponse({ error: '找不到名為「商品清單」的工作表，請確認工作表名稱正確。' });
  }

  const range = sheet.getDataRange();
  const data = range.getValues();

  if (data.length < 2) {
    return createJsonResponse([]);
  }

  // 取得標題並修剪空格
  const headers = data[0].map(h => h.toString().trim());

  // 處理資料行
  const products = data.slice(1).map((row) => {
    // 檢查是否為空行 (如果整行都是空的就跳過)
    if (row.every(cell => cell === "")) return null;

    let obj = {};
    headers.forEach((header, i) => {
      let value = row[i];

      // 針對特定欄位進行強制類型轉換
      if (['price', 'original_price', 'stock'].includes(header)) {
        const numValue = Number(value);
        value = isNaN(numValue) ? 0 : numValue;
      }

      // 處理布林值或 null
      if (value === null || value === undefined) value = "";

      obj[header] = value;
    });
    return obj;
  })
  .filter(p => p !== null) // 過濾掉空行
  .filter(p => {
    // 僅回傳狀態為 Active 的商品 (不分大小寫)
    const status = (p.status || "").toString().trim().toLowerCase();
    return status === 'active';
  });

  console.log('成功讀取商品數量:', products.length);
  return createJsonResponse(products);
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  // 後續實作訂單與會員邏輯
  return createJsonResponse({ message: 'POST 請求已收到' });
}

