  const products = data.slice(1).map((row, index) => {
    // 檢查是否為空行
    if (row.every(cell => cell === "")) return null;

    let obj = {};
    headers.forEach((header, i) => {
      let value = row[i];

      // 針對數字欄位進行轉換
      const numericFields = ['price', 'original_price', 'stock'];
      if (numericFields.includes(header)) {
        const numValue = Number(value);
        value = isNaN(numValue) ? 0 : numValue;
      }

      // 處理 null 或 undefined
      if (value === null || value === undefined) value = "";

      obj[header] = value;
    });
    return obj;
  })
  .filter(p => p !== null) // 移除空行
  .filter(p => {
    // 僅回傳狀態為 Active 的商品
    // 欄位名稱對應會受標題大小寫影響，這裡使用 headers 處理過的小寫
    const statusVal = (p['status'] || "").toString().trim().toLowerCase();
    const isActive = statusVal === 'active';
    return isActive;
  });

  console.log('符合 Active 狀態並準備回傳的商品數量:', products.length);
  if (products.length > 0) {
    console.log('第一筆商品範例:', JSON.stringify(products[0]));
  } else {
    console.warn('沒有任何商品的 status 為 Active');
  }

  return createJsonResponse(products);
}

