  let ss;
  try {
    ss = SpreadsheetApp.openById(PRODUCT_SHEET_ID);
  } catch (e) {
    return createJsonResponse({ error: '無法開啟試算表，請確認 ID 正確且已開放存取權限給「任何人」。' });
  }

  const allSheets = ss.getSheets();
  const allSheetNames = allSheets.map(s => s.getName());
  console.log('[SHEET_DEBUG] 現有的分頁名稱:', allSheetNames.join(', '));

  let sheet = null;
  const targetName = '商品清單';

  // 1. 嘗試精準匹配
  sheet = ss.getSheetByName(targetName);

  // 2. 嘗試模糊匹配 (包含 "商品" 或 "清單")
  if (!sheet) {
    console.warn('[SHEET_DEBUG] 找不到精準名稱，啟動模糊搜尋...');
    sheet = allSheets.find(s => s.getName().includes('商品') || s.getName().includes('清單'));
  }

  // 3. 保底方案：取第一個分頁
  if (!sheet && allSheets.length > 0) {
    console.warn('[SHEET_DEBUG] 模糊搜尋失敗，自動抓取第一個分頁。');
    sheet = allSheets[0];
  }

  if (!sheet) {
    return createJsonResponse({ 
      error: '找不到任何有效的工作表', 
      availableSheets: allSheetNames 
    });
  }

  const activeSheetName = sheet.getName();
  console.log('[SHEET_DEBUG] 最終使用的分頁名稱:', activeSheetName);

  const range = sheet.getDataRange();
  const data = range.getValues();

  if (data.length < 2) {
    console.warn('[SHEET_DEBUG] 工作表內容不足（少於兩列）');
    return createJsonResponse([]);
  }

  // 處理標題：修剪空格、轉小寫
  const headers = data[0].map(h => h.toString().trim().toLowerCase());

  const products = data.slice(1).map((row) => {
    if (row.every(cell => cell === "")) return null;

    let obj = {};
    headers.forEach((header, i) => {
      let value = row[i];
      const numericFields = ['price', 'original_price', 'stock'];
      if (numericFields.includes(header)) {
        const numValue = Number(value);
        value = isNaN(numValue) ? 0 : numValue;
      }
      obj[header] = value;
    });
    return obj;
  })
  .filter(p => p !== null)
  .filter(p => {
    // 容錯處理：如果沒有 status 欄位，預設顯示；如果有，則過濾 Active
    if (!p.status) return true;
    return p.status.toString().trim().toLowerCase() === 'active';
  });

  console.log('[SHEET_DEBUG] 成功解析商品數量:', products.length);
  return createJsonResponse(products);
}

function createJsonResponse(data) {
