  }

  const allSheets = ss.getSheets();
  let targetSheet = null;
  let detectedHeaders = [];

  // 智慧掃描：檢查所有分頁，尋找包含 product_id 的那一張
  for (let s of allSheets) {
    const tempName = s.getName();
    const tempData = s.getRange(1, 1, 1, s.getLastColumn()).getValues()[0];
    const tempHeaders = tempData.map(h => h.toString().trim().toLowerCase());

    console.log('[SCAN] 檢查分頁: "' + tempName + '", 標題為: ' + tempHeaders.join('|'));

    if (tempHeaders.includes('product_id')) {
      targetSheet = s;
      detectedHeaders = tempHeaders;
      console.log('[SCAN] >>> 找到目標分頁: ' + tempName);
      break;
    }
  }

  // 如果掃描失敗，嘗試保底方案：取第一個分頁
  if (!targetSheet && allSheets.length > 0) {
    targetSheet = allSheets[0];
    const rawData = targetSheet.getRange(1, 1, 1, targetSheet.getLastColumn()).getValues()[0];
    detectedHeaders = rawData.map(h => h.toString().trim().toLowerCase());
    console.warn('[SCAN] 未找到匹配標題的分頁，強制取第一個分頁: ' + targetSheet.getName());
  }

  if (!targetSheet) {
    return createJsonResponse({ error: '試算表內沒有任何分頁。' });
  }

  const data = targetSheet.getDataRange().getValues();
  if (data.length < 2) {
    return createJsonResponse({ error: '分頁「' + targetSheet.getName() + '」內沒有商品資料（僅有標題或全空）。' });
  }

  const products = data.slice(1).map((row, rowIndex) => {
    // 檢查是否為空行
    if (row.every(cell => cell === "" || cell === null)) return null;

    let obj = {};
    detectedHeaders.forEach((header, i) => {
      if (!header) return; // 略過無標題的欄位

      let value = row[i];
      // 數字轉型
      const numericFields = ['price', 'original_price', 'stock'];
      if (numericFields.includes(header)) {
        const numValue = Number(value);
        value = isNaN(numValue) ? 0 : numValue;
      }
      obj[header] = value;
    });
    return obj;
  })
  .filter(p => p !== null)
  .filter(p => {
    // 過濾 Active 狀態
    const statusVal = (p['status'] || "").toString().trim().toLowerCase();
    return statusVal === 'active' || statusVal === ''; // 如果沒填狀態預設顯示
  });

  console.log('[SUCCESS] 最終回傳商品數:', products.length);
  return createJsonResponse(products);
}

function createJsonResponse(data) {
