/**
 * Google Apps Script 後端 - 維力萃 Vitality Nutraceuticals
 * 
 * 版本：3.0 (極致容錯版)
 * 
 * 修正重點：
 * 1. 即使分頁名稱不是「商品清單」也能運作。
 * 2. 支援中英文標題對應 (例如 product_id 或 商品編號)。
 * 3. 增加詳盡的 JSON 錯誤回傳，方便前端排查。
 */

const PRODUCT_SHEET_ID = '1AxzphT6sT3CYTwFDlhFftfZhLJh_OCfjCmxfF9I918U';

function doGet(e) {
  const action = e.parameter.action || 'getProducts';
  console.log('[API] 收到請求 Action:', action);

  try {
    if (action === 'getProducts') {
      return getProducts();
    }
    return createJsonResponse({ error: '未知的指令: ' + action });
  } catch (error) {
    console.error('[CRITICAL]', error);
    return createJsonResponse({ 
      error: '伺服器端發生錯誤', 
      details: error.toString(),
      sheetId: PRODUCT_SHEET_ID
    });
  }
}

function getProducts() {
  let ss;
  try {
    ss = SpreadsheetApp.openById(PRODUCT_SHEET_ID);
  } catch (e) {
    return createJsonResponse({ 
      error: '無法開啟試算表', 
      details: '請確認試算表 ID 正確，且已設定「知道連結的人」可以檢視。',
      id_tried: PRODUCT_SHEET_ID
    });
  }

  const allSheets = ss.getSheets();
  const allSheetNames = allSheets.map(s => s.getName());
  console.log('[SCAN] 所有分頁:', allSheetNames.join(', '));

  let targetSheet = null;
  let headers = [];

  // 智慧比對標題關鍵字 (支援中英文)
  const idKeywords = ['product_id', 'id', '商品編號', '編號', '序號'];

  // 1. 遍歷所有分頁尋找包含 ID 欄位的分頁
  for (let s of allSheets) {
    const lastCol = Math.max(1, s.getLastColumn());
    const firstRow = s.getRange(1, 1, 1, lastCol).getValues()[0];
    const normalizedRow = firstRow.map(h => h.toString().trim().toLowerCase());

    // 如果這張表的標題包含了任何一個 ID 關鍵字
    if (normalizedRow.some(h => idKeywords.includes(h))) {
      targetSheet = s;
      headers = normalizedRow;
      console.log('[SCAN] 找到匹配分頁:', s.getName());
      break;
    }
  }

  // 2. 如果沒找到標題匹配，且有分頁名稱叫「商品清單」，強行嘗試
  if (!targetSheet) {
    targetSheet = ss.getSheetByName('商品清單');
    if (targetSheet) {
      headers = targetSheet.getRange(1, 1, 1, Math.max(1, targetSheet.getLastColumn())).getValues()[0]
                .map(h => h.toString().trim().toLowerCase());
      console.log('[SCAN] 依名稱找到分頁: 商品清單');
    }
  }

  // 3. 保底方案：取第一個分頁
  if (!targetSheet && allSheets.length > 0) {
    targetSheet = allSheets[0];
    headers = targetSheet.getRange(1, 1, 1, Math.max(1, targetSheet.getLastColumn())).getValues()[0]
              .map(h => h.toString().trim().toLowerCase());
    console.log('[SCAN] 最終保底取第一個分頁:', targetSheet.getName());
  }

  if (!targetSheet) {
    return createJsonResponse({ 
      error: '找不到有效的工作表', 
      available_sheets: allSheetNames 
    });
  }

  const data = targetSheet.getDataRange().getValues();
  if (data.length < 2) {
    return createJsonResponse({ error: '分頁內容不足（無資料列）', sheet_name: targetSheet.getName() });
  }

  // 標題與物件 key 的對應轉換 (處理中文標題轉英文 key)
  const keyMap = {
    '商品編號': 'product_id', '編號': 'product_id', 'id': 'product_id',
    '名稱': 'name', '商品名稱': 'name',
    '分類': 'category', '類別': 'category',
    '價格': 'price', '售價': 'price',
    '原價': 'original_price',
    '庫存': 'stock', '數量': 'stock',
    '圖片': 'image_url', '圖片網址': 'image_url', 'image': 'image_url',
    '描述': 'description', '介紹': 'description',
    '規格': 'spec', '單位': 'spec',
    '狀態': 'status'
  };

  const products = data.slice(1).map((row) => {
    if (row.every(cell => cell === "" || cell === null)) return null;

    let obj = {};
    headers.forEach((header, i) => {
      let key = keyMap[header] || header; // 優先轉換，否則用原標題
      let value = row[i];

      // 處理數字型態
      if (['price', 'original_price', 'stock'].includes(key)) {
        value = Number(value) || 0;
      }
      obj[key] = value;
    });
    return obj;
  })
  .filter(p => p !== null)
  .filter(p => {
    // 預設只要有名字就顯示
    if (!p.name) return false;
    const status = (p.status || "").toString().trim().toLowerCase();
    return status === 'active' || status === '啟用' || status === '';
  });

  console.log('[API] 回傳商品數:', products.length);
  return createJsonResponse(products);
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

