/**
 * 維力萃 Vitality Nutraceuticals - Google Apps Script 後端系統
 * 
 * 核心功能：
 * 1. getProducts: 智慧掃描商品清單，支援中英文標題。
 * 2. register/login: 會員系統。
 * 3. createOrder: 訂單建立與庫存自動扣減。
 * 
 * 安全設定：
 * - 部署時請選擇「Web App」。
 * - 執行身分：我 (Me)。
 * - 誰可以存取：任何人 (Anyone)。
 */

const PRODUCT_SHEET_ID = '1AxzphT6sT3CYTwFDlhFftfZhLJh_OCfjCmxfF9I918U';
const MEMBER_SHEET_ID = '1_BseP1u7W5C6ulUkJ1kMPHu7gIJWpRbY-vxCovNunDo';
const ORDER_SHEET_ID = '1AEBWFkF1yyZe3z6E1qTAkxhpMm04YlexI-PlNoXC0Yg';

/**
 * 處理 GET 請求
 */
function doGet(e) {
  const action = e.parameter.action;

  try {
    switch (action) {
      case 'getProducts':
        return getProducts();
      case 'getMemberProfile':
        return getMemberProfile(e.parameter.email);
      case 'getOrderHistory':
        return getOrderHistory(e.parameter.member_id);
      default:
        return createJsonResponse({ error: '未知的 Action 指令' });
    }
  } catch (err) {
    return createJsonResponse({ error: '系統異常', details: err.toString() });
  }
}

/**
 * 處理 POST 請求
 */
function doPost(e) {
  let postData;
  try {
    postData = JSON.parse(e.postData.contents);
  } catch (f) {
    // 兼容 Form 格式
    postData = e.parameter;
  }

  const action = postData.action;

  try {
    switch (action) {
      case 'register':
        return registerMember(postData);
      case 'login':
        return loginMember(postData.email, postData.password);
      case 'createOrder':
        return createOrder(postData);
      default:
        return createJsonResponse({ error: '未知的 Post Action' });
    }
  } catch (err) {
    return createJsonResponse({ error: '處理請求時發生錯誤', details: err.toString() });
  }
}

/**
 * 智慧獲取商品列表 (具備高度容錯)
 */
function getProducts() {
  const ss = SpreadsheetApp.openById(PRODUCT_SHEET_ID);
  const sheet = findBestSheet(ss, ['product_id', '商品編號', 'id']);

  if (!sheet) return createJsonResponse({ error: '找不到有效的工作表，請確認是否有標題為 product_id 的分頁。' });

  const data = sheet.getDataRange().getValues();
  const headers = data[0].map(h => h.toString().trim().toLowerCase());

  const keyMap = {
    'product_id': 'product_id', '商品編號': 'product_id', 'id': 'product_id',
    'name': 'name', '名稱': 'name', '商品名稱': 'name',
    'category': 'category', '分類': 'category', '類別': 'category',
    'price': 'price', '價格': 'price', '售價': 'price',
    'original_price': 'original_price', '原價': 'original_price',
    'stock': 'stock', '庫存': 'stock', '數量': 'stock',
    'image_url': 'image_url', '圖片網址': 'image_url', 'image': 'image_url',
    'description': 'description', '描述': 'description', '介紹': 'description',
    'spec': 'spec', '規格': 'spec',
    'status': 'status', '狀態': 'status'
  };

  const products = data.slice(1).map(row => {
    if (row.every(cell => cell === "")) return null;
    let obj = {};
    headers.forEach((h, i) => {
      let key = keyMap[h] || h;
      let val = row[i];
      if (['price', 'original_price', 'stock'].includes(key)) val = Number(val) || 0;
      obj[key] = val;
    });
    return obj;
  }).filter(p => p !== null && (p.status === 'Active' || p.status === '啟用' || p.status === '' || !p.status));

  return createJsonResponse(products);
}

/**
 * 會員註冊
 */
function registerMember(data) {
  const ss = SpreadsheetApp.openById(MEMBER_SHEET_ID);
  const sheet = ss.getSheets()[0];
  const members = sheet.getDataRange().getValues();

  // 檢查 Email 是否重複 (假設 Email 在第 2 欄)
  const emailIndex = 1; 
  if (members.some(row => row[emailIndex] === data.email)) {
    return createJsonResponse({ error: '此電子郵件已被註冊' });
  }

  const memberId = 'M' + new Date().getTime();
  const createdAt = new Date();

  // [member_id, email, password, full_name, phone, address, member_level, created_at]
  sheet.appendRow([
    memberId, 
    data.email, 
    data.password, 
    data.full_name, 
    data.phone, 
    data.address, 
    'Standard', 
    createdAt
  ]);

  return createJsonResponse({ success: true, member_id: memberId });
}

/**
 * 會員登入
 */
function loginMember(email, password) {
  const ss = SpreadsheetApp.openById(MEMBER_SHEET_ID);
  const sheet = ss.getSheets()[0];
  const data = sheet.getDataRange().getValues();

  const user = data.find(row => row[1] === email && row[2] === password);

  if (user) {
    return createJsonResponse({
      success: true,
      member: {
        member_id: user[0],
        email: user[1],
        full_name: user[3],
        member_level: user[6]
      }
    });
  } else {
    return createJsonResponse({ error: '帳號或密碼錯誤' });
  }
}

/**
 * 建立訂單並扣減庫存
 */
function createOrder(data) {
  const orderSs = SpreadsheetApp.openById(ORDER_SHEET_ID);
  const orderSheet = orderSs.getSheets()[0];
  const orderId = 'ORD' + new Date().getTime();

  // 1. 寫入訂單
  // [order_id, member_id, order_date, total_amount, items_json, shipping_status, payment_status, receiver_name, receiver_phone, shipping_address]
  orderSheet.appendRow([
    orderId,
    data.member_id,
    new Date(),
    data.total_amount,
    JSON.stringify(data.items),
    'Pending',
    'Unpaid',
    data.receiver_name,
    data.receiver_phone,
    data.shipping_address
  ]);

  // 2. 扣減庫存邏輯
  const productSs = SpreadsheetApp.openById(PRODUCT_SHEET_ID);
  const productSheet = findBestSheet(productSs, ['product_id', '商品編號', 'id']);
  const productData = productSheet.getDataRange().getValues();
  const headers = productData[0].map(h => h.toString().trim().toLowerCase());

  const idCol = headers.indexOf('product_id') === -1 ? headers.indexOf('id') : headers.indexOf('product_id');
  const stockCol = headers.indexOf('stock') === -1 ? headers.indexOf('庫存') : headers.indexOf('stock');

  data.items.forEach(item => {
    for (let i = 1; i < productData.length; i++) {
      if (productData[i][idCol].toString() === item.product_id.toString()) {
        const currentStock = Number(productData[i][stockCol]) || 0;
        const newStock = Math.max(0, currentStock - item.quantity);
        productSheet.getRange(i + 1, stockCol + 1).setValue(newStock);
        break;
      }
    }
  });

  return createJsonResponse({ success: true, order_id: orderId });
}

/**
 * 輔助函數：智慧尋找最適合的工作表
 */
function findBestSheet(ss, keywords) {
  const sheets = ss.getSheets();
  for (let s of sheets) {
    const firstRow = s.getRange(1, 1, 1, Math.max(1, s.getLastColumn())).getValues()[0]
                      .map(h => h.toString().trim().toLowerCase());
    if (keywords.some(k => firstRow.includes(k))) return s;
  }
  return sheets[0]; // 找不到就給第一個
}

/**
 * 輔助函數：建立標準 JSON 回傳
 */
function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

/**
 * 維力萃 Vitality Nutraceuticals - Google Apps Script 後端系統 (全量抓取版)
 */

const PRODUCT_SHEET_ID = '1AxzphT6sT3CYTwFDlhFftfZhLJh_OCfjCmxfF9I918U';

function doGet(e) {
  const action = e.parameter.action || 'getProducts';
  console.log('[API] 執行動作:', action);

  try {
    if (action === 'getProducts') {
      return getProducts();
    }
    return createJsonResponse({ error: '未知的 Action: ' + action });
  } catch (err) {
    console.error('[SERVER_ERROR]', err);
    return createJsonResponse({ error: '伺服器錯誤', details: err.toString() });
  }
}

function getProducts() {
  const ss = SpreadsheetApp.openById(PRODUCT_SHEET_ID);

  // 1. 優先尋找名為「商品清單」的分頁
  let sheet = ss.getSheetByName('商品清單');

  // 2. 如果找不到，則尋找包含 product_id 標題的分頁
  if (!sheet) {
    const sheets = ss.getSheets();
    for (let s of sheets) {
      const firstRow = s.getRange(1, 1, 1, Math.max(1, s.getLastColumn())).getValues()[0]
                        .map(h => h.toString().trim().toLowerCase());
      if (firstRow.includes('product_id') || firstRow.includes('商品編號')) {
        sheet = s;
        break;
      }
    }
  }

  // 3. 最終保底：使用第一個分頁
  if (!sheet) sheet = ss.getSheets()[0];

  console.log('[SCAN] 使用分頁:', sheet.getName());

  const data = sheet.getDataRange().getValues();
  if (data.length < 2) return createJsonResponse({ error: '分頁內無商品資料' });

  const headers = data[0].map(h => h.toString().trim().toLowerCase());

  // 欄位對應表 (增加更多變體以防萬一)
  const keyMap = {
    'product_id': 'product_id', '商品編號': 'product_id', 'id': 'product_id', '序號': 'product_id',
    'name': 'name', '名稱': 'name', '商品名稱': 'name', '品名': 'name',
    'category': 'category', '分類': 'category', '類別': 'category',
    'price': 'price', '價格': 'price', '售價': 'price', '金額': 'price',
    'original_price': 'original_price', '原價': 'original_price', '建議售價': 'original_price',
    'stock': 'stock', '庫存': 'stock', '數量': 'stock', '剩餘': 'stock',
    'image_url': 'image_url', '圖片網址': 'image_url', '圖片': 'image_url', '網址': 'image_url',
    'description': 'description', '描述': 'description', '介紹': 'description', '簡介': 'description',
    'spec': 'spec', '規格': 'spec', '容量': 'spec', '單位': 'spec',
    'status': 'status', '狀態': 'status'
  };

  const products = data.slice(1).map((row, idx) => {
    // 檢查是否整行空值
    if (row.every(cell => cell === "" || cell === null)) return null;

    let obj = {};
    headers.forEach((h, i) => {
      let key = keyMap[h] || h;
      let val = row[i];

      // 類型強制轉換
      if (['price', 'original_price', 'stock'].includes(key)) {
        const num = Number(val);
        val = isNaN(num) ? 0 : num;
      }
      obj[key] = val;
    });

    // 補齊必要欄位
    if (!obj.product_id) obj.product_id = 'AUTO_' + idx;
    if (!obj.image_url) obj.image_url = 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?q=80&w=400';

    return obj;
  })
  .filter(p => p !== null)
  .filter(p => {
    // 過濾掉明顯不完整的資料 (例如沒名字的)
    if (!p.name) return false;
    // 狀態過濾 (除非明確認定為 Inactive 或 停用，否則全部顯示)
    const statusStr = (p.status || "").toString().trim().toLowerCase();
    return statusStr !== 'inactive' && statusStr !== '停用' && statusStr !== '下架';
  });

  console.log('[SUCCESS] 回傳商品總數:', products.length);
  return createJsonResponse(products);
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

import React, { useState, useEffect, useCallback } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import ProductCard from './components/ProductCard';
import { Product, CartItem } from './types';
import { X, ChevronRight, ShoppingBag, ArrowLeft, Loader2, AlertCircle, RefreshCw } from 'lucide-react';

type View = 'Home' | 'ProductDetail' | 'Cart' | 'Login' | 'Account';

// 注意：請確保此 URL 為最新部署的網址
const GAS_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbzZKdUNXPIPixpQqAHoQz5WZJiJGN2VSastd8XAfHfNnnGxPYqej4I5y7KktYQ_KHqu/exec';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('Home');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<{ message: string; details?: string } | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  const fetchProducts = useCallback(async () => {
    setIsLoading(true);
    setError(null);

    try {
      console.log('[APP] 正在從 GAS 獲取商品清單...');
      const response = await fetch(`${GAS_WEB_APP_URL}?action=getProducts&timestamp=${Date.now()}`);

      if (!response.ok) throw new Error(`HTTP 錯誤: ${response.status}`);

      const data = await response.json();

      if (data.error) {
        throw new Error(data.error);
      }

      if (Array.isArray(data)) {
        console.log(`[APP] 成功讀取 ${data.length} 個商品:`, data);
        setProducts(data);
      } else {
        throw new Error('接收到的資料格式非陣列');
      }
    } catch (err: any) {
      console.error('[APP_ERROR]', err);
      setError({ message: '連線至試算表失敗', details: err.message });
      // 失敗時使用 Mock 資料保底
      const { MOCK_PRODUCTS } = await import('./data/mockData');
      setProducts(MOCK_PRODUCTS);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchProducts();
  }, [fetchProducts]);

  useEffect(() => {
    const savedCart = localStorage.getItem('vnutra_cart');
    if (savedCart) {
      try { setCart(JSON.parse(savedCart)); } catch (e) {}
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('vnutra_cart', JSON.stringify(cart));
  }, [cart]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product_id === product.product_id);
      if (existing) {
        return prev.map(item => item.product_id === product.product_id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (productId: string) => setCart(prev => prev.filter(item => item.product_id !== productId));
  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => item.product_id === productId ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item));
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen">
      <Header 
        cartCount={cartCount} 
        onCartClick={() => setIsCartOpen(true)}
        onUserClick={() => setCurrentView('Login')}
        onHomeClick={() => { setCurrentView('Home'); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
      />

      <main className="pt-[72px]">
        {currentView === 'Home' && (
