 */
function formatDriveImageUrl(url) {
  if (!url) return "";
  const strUrl = url.toString().trim();

  // 如果是 Google Drive 連結
  if (strUrl.includes('drive.google.com')) {
    let fileId = "";

    // 處理 /file/d/FILE_ID/view 格式
    if (strUrl.includes('/file/d/')) {
      fileId = strUrl.split('/file/d/')[1].split('/')[0];
    } 
    // 處理 ?id=FILE_ID 格式
    else if (strUrl.includes('id=')) {
      fileId = strUrl.split('id=')[1].split('&')[0];
