 */
function formatDriveImageUrl(url) {
  if (!url) return "";
  var strUrl = url.toString().trim();

  // 如果是 Google Drive 連結
  if (strUrl.indexOf('drive.google.com') > -1) {
    // 排除資料夾 (資料夾無法顯示為圖片)
    if (strUrl.indexOf('/folders/') > -1) return "";

    // 提取 ID：尋找 33 字元或以上的 ID 字串
    var matches = strUrl.match(/[-\w]{33,}/);
    if (!matches) {
      // 嘗試較短的 ID 格式
      matches = strUrl.match(/[-\w]{25,}/);
    }

    if (matches && matches[0]) {
      var fileId = matches[0];
      // 使用 lh3.googleusercontent.com/d/ID 格式，這是目前最穩定的外連方式
      return "https://lh3.googleusercontent.com/d/" + fileId;
    }
  }

  return strUrl;
}

