/**
 * 格式化 Google Drive 連結為直接顯示 URL
 */
function formatDriveImageUrl(url) {
  if (!url) return "";
  var strUrl = url.toString().trim();

  // 如果已經是正確的格式或非 Google Drive 連結，直接回傳
  if (strUrl.startsWith('http') && strUrl.indexOf('drive.google.com') === -1 && strUrl.indexOf('docs.google.com') === -1) {
    return strUrl;
  }

  // 處理 Google Drive 連結
  if (strUrl.indexOf('drive.google.com') > -1 || strUrl.indexOf('docs.google.com') > -1) {
    // 排除資料夾連結
    if (strUrl.indexOf('/folders/') > -1) return "";

    // 提取 ID 的通用正規表達式
    // 1. 匹配 /d/ID/ 格式
    // 2. 匹配 id=ID 格式
    var idMatch = strUrl.match(/\/d\/([-\w]{25,})/) || strUrl.match(/[?&]id=([-\w]{25,})/);
    var fileId = idMatch ? idMatch[1] : null;

    // 如果沒匹配到，嘗試直接匹配長字串 (假設整串就是 ID 或包含 ID)
    if (!fileId) {
      var longStrMatch = strUrl.match(/([-\w]{25,})/);
      if (longStrMatch) fileId = longStrMatch[1];
    }

    if (fileId) {
      // 使用 uc?id= 介面，這是目前在 Web App 中引用 Drive 圖片最簡單且廣泛支援的方式
      return "https://drive.google.com/uc?export=view&id=" + fileId;
    }
  }

  // 如果是純 ID (長度大於 25 且不含斜線)
  if (strUrl.length >= 25 && strUrl.indexOf('/') === -1) {
    return "https://drive.google.com/uc?export=view&id=" + strUrl;
  }

  return strUrl;
}

