 */
function registerMember(data) {
  const ss = SpreadsheetApp.openById(MEMBER_SHEET_ID);
  let sheet = ss.getSheetByName('會員清單') || ss.getSheets()[0];

  const values = sheet.getDataRange().getValues();
  const headers = values[0];
  const emailIndex = headers.indexOf('email');

  // 1. 檢查 Email 是否已存在
  if (emailIndex !== -1) {
    for (let i = 1; i < values.length; i++) {
      if (values[i][emailIndex] === data.email) {
        return createJsonResponse({ error: '此電子郵件已被註冊' });
      }
    }
  }

  // 2. 準備新會員資料
  const newId = 'M' + new Date().getTime();
  const createdAt = new Date().toISOString();

  // 依照欄位順序準備資料: member_id, email, password, full_name, phone, address, member_level, created_at
  const newRow = [
    newId,
    data.email,
    data.password, // 建議生產環境加密
    data.full_name || '',
    data.phone || '',
    data.address || '',
    'Regular',
    createdAt
  ];

  // 3. 寫入試算表
  sheet.appendRow(newRow);

  return createJsonResponse({ 
    success: true, 
    member: {
      member_id: newId,
      email: data.email,
      full_name: data.full_name,
      member_level: 'Regular'
    }
  });
}

