        {currentView === 'Home' && (
          <div className="fade-in">
            <Hero />
            <section className="py-24 bg-white">
              <div className="container mx-auto px-6">
                <div className="flex items-end justify-between mb-16">
                  <div>
                    <span className="text-[10px] uppercase tracking-[0.4em] text-gray-400 mb-2 block font-medium">精確配方專研</span>
                    <h2 className="text-4xl md:text-5xl serif tracking-wide">精選系列</h2>
                  </div>
                  <button onClick={fetchProducts} className="flex items-center space-x-2 text-[10px] uppercase tracking-widest text-gray-300 hover:text-gray-900 transition-colors">
                    <RefreshCw className={`w-3 h-3 ${isLoading ? 'animate-spin' : ''}`} />
                    <span>同步雲端資料</span>
                  </button>
                </div>

                {isLoading ? (
                  <div className="flex flex-col items-center justify-center py-40 space-y-6">
                    <Loader2 className="w-8 h-8 animate-spin text-gray-100 stroke-1" />
