              </div>
              <div className="flex flex-col justify-center">
                <span className="text-[10px] uppercase tracking-[0.4em] text-gray-400 font-medium mb-4 block">{selectedProduct.category}</span>
                <h1 className="text-5xl serif mb-6 tracking-wide leading-tight">{selectedProduct.name}</h1>
                <div className="flex items-baseline space-x-4 mb-8 border-b border-gray-100 pb-8">
                  <span className="text-2xl font-light tracking-widest">NT$ {selectedProduct.price.toLocaleString()}</span>
                  {selectedProduct.original_price > selectedProduct.price && (
                    <span className="text-lg text-gray-300 line-through">NT$ {selectedProduct.original_price.toLocaleString()}</span>
                  )}
                </div>
                <p className="text-gray-600 leading-relaxed font-light mb-12 text-lg">{selectedProduct.description}</p>
                <div className="space-y-4">
                  <div className="flex items-center justify-between text-[10px] uppercase tracking-widest text-gray-400 mb-2">
                    <span>規格容量</span>
                    <span className="text-gray-900">{selectedProduct.spec}</span>
                  </div>
                  <button onClick={() => addToCart(selectedProduct)} className="w-full bg-gray-900 text-white py-6 text-[10px] uppercase tracking-[0.3em] hover:bg-black transition-all">
                    加入我的購物袋
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Cart Sidebar */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[100] overflow-hidden">
          <div className="absolute inset-0 bg-black/10 backdrop-blur-[2px]" onClick={() => setIsCartOpen(false)}></div>
          <div className="absolute top-0 right-0 bottom-0 w-full max-w-md bg-white shadow-2xl flex flex-col transform transition-transform duration-700 ease-in-out">
            <div className="px-10 py-12 flex items-center justify-between border-b border-gray-50">
              <h2 className="text-xl serif tracking-widest uppercase">我的購物袋 ({cartCount})</h2>
              <button onClick={() => setIsCartOpen(false)} className="p-2 hover:opacity-50"><X className="w-5 h-5" /></button>
            </div>
            <div className="flex-1 overflow-y-auto px-10 py-8 space-y-10">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center space-y-6">
                  <ShoppingBag className="w-16 h-16 text-gray-50 stroke-1" />
                  <p className="text-[10px] tracking-[0.3em] text-gray-300 uppercase">購物袋目前尚無挑選商品</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.product_id} className="flex space-x-8">
                    <div className="w-24 h-30 bg-gray-50 flex-shrink-0"><img src={item.image_url} className="w-full h-full object-cover" /></div>
                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div>
                        <div className="flex justify-between items-start mb-2">
                          <h4 className="text-sm font-medium tracking-wide text-gray-900 leading-snug">{item.name}</h4>
                          <button onClick={() => removeFromCart(item.product_id)} className="text-gray-300 hover:text-red-500"><X className="w-4 h-4" /></button>
                        </div>
                        <span className="text-[9px] uppercase tracking-widest text-gray-400">{item.category}</span>
                      </div>
                      <div className="flex items-center justify-between mt-4">
                        <div className="flex items-center border border-gray-100 rounded-sm">
                          <button onClick={() => updateQuantity(item.product_id, -1)} className="px-3 py-1 text-gray-400">-</button>
                          <span className="px-2 text-[11px] font-medium">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.product_id, 1)} className="px-3 py-1 text-gray-400">+</button>
                        </div>
                        <span className="text-xs font-medium tracking-widest">NT$ {(item.price * item.quantity).toLocaleString()}</span>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
            {cart.length > 0 && (
              <div className="px-10 py-12 bg-white border-t border-gray-50">
                <div className="flex items-center justify-between mb-10"><span className="text-[10px] tracking-[0.3em] font-medium uppercase text-gray-400">訂單小計</span><span className="text-2xl serif font-light">NT$ {cartTotal.toLocaleString()}</span></div>
                <button className="w-full bg-gray-900 text-white py-6 text-[10px] uppercase tracking-[0.4em] font-semibold hover:bg-black transition-all flex items-center justify-center space-x-4"><span>進行安全結帳流程</span><ChevronRight className="w-4 h-4" /></button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

