import React, { useState, useEffect, useCallback } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import ProductCard from './components/ProductCard';
import { Product, CartItem, Member } from './types';
import { X, ChevronRight, ShoppingBag, ArrowLeft, Loader2, AlertCircle, RefreshCw, CheckCircle2, LogOut, User as UserIcon, Settings, History, CreditCard, Heart } from 'lucide-react';

type View = 'Home' | 'ProductDetail' | 'Cart' | 'Login' | 'Account';
type AuthMode = 'Login' | 'Register';

const GAS_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbzBphMCZ8eQ3ye4RA3okuKz92qfZ8UwPvrfs-bd2TnEgSFvrkE6-r8dS9ONDMOOQhAm/exec';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('Home');
  const [authMode, setAuthMode] = useState<AuthMode>('Login');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<{ message: string; details?: string } | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [user, setUser] = useState<Partial<Member> | null>(null);

  const [authFormData, setAuthFormData] = useState({
    email: '',
    password: '',
    full_name: '',
    phone: '',
    address: '',
    gender: '',
    birthday: '',
  });

  const fetchProducts = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=getProducts&timestamp=${Date.now()}`);
      const data = await response.json();
      if (data.error) throw new Error(data.error);
      setProducts(Array.isArray(data) ? data : []);
    } catch (err: any) {
      console.error('[APP_ERROR]', err);
      // Fallback to local mock data if GAS fails
      const { MOCK_PRODUCTS } = await import('./data/mockData');
      setProducts(MOCK_PRODUCTS);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchProducts(); }, [fetchProducts]);

  useEffect(() => {
    const savedCart = localStorage.getItem('cining_cart');
    if (savedCart) try { setCart(JSON.parse(savedCart)); } catch (e) {}
    const savedUser = sessionStorage.getItem('cining_user');
    if (savedUser) try { setUser(JSON.parse(savedUser)); } catch (e) {}
  }, []);

  useEffect(() => { localStorage.setItem('cining_cart', JSON.stringify(cart)); }, [cart]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product_id === product.product_id);
      if (existing) return prev.map(item => item.product_id === product.product_id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (productId: string) => setCart(prev => prev.filter(item => item.product_id !== productId));
  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => item.product_id === productId ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item));
  };

  const handleLogout = () => {
    setUser(null);
    sessionStorage.removeItem('cining_user');
    setCurrentView('Home');
  };

  const handleAuthSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    setSuccessMsg(null);

    const payload = {
      action: authMode === 'Register' ? 'register' : 'login',
      ...authFormData
    };

    try {
      const response = await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(payload),
      });
      const result = await response.json();
      if (result.error) throw new Error(result.error);

      if (authMode === 'Register') {
        setSuccessMsg('帳號已成功建立。現在您可以登入了。');
        setAuthMode('Login');
        setAuthFormData(prev => ({ ...prev, password: '' }));
      } else {
        if (result.member) {
          setUser(result.member);
          sessionStorage.setItem('cining_user', JSON.stringify(result.member));
          setSuccessMsg('驗證成功，歡迎回到南海慈寧宮。');
          setTimeout(() => {
            setCurrentView('Home');
            setSuccessMsg(null);
          }, 1500);
        }
      }
    } catch (err: any) {
      setError({ message: err.message, details: '請確認帳號密碼是否正確。' });
    } finally {
      setIsSubmitting(false);
    }
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen bg-[#fffdf9]">
      <Header 
        cartCount={cartCount} 
        onCartClick={() => setIsCartOpen(true)}
        onUserClick={() => user ? setCurrentView('Account') : setCurrentView('Login')}
        onHomeClick={() => { setCurrentView('Home'); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
        user={user}
      />

      <main className="pt-0">
        {currentView === 'Home' && (
          <div className="fade-in">
            <Hero />
            <section className="py-24 bg-white border-y border-orange-100 relative overflow-hidden">
               {/* Decorative background element */}
              <div className="absolute top-0 right-0 w-64 h-64 bg-[#8B0000]/5 rounded-full -translate-y-1/2 translate-x-1/2"></div>

              <div className="container mx-auto px-6 relative z-10">
                <div className="flex flex-col md:flex-row md:items-end justify-between mb-20 gap-8">
                  <div className="max-w-xl">
                    <span className="text-[11px] uppercase tracking-[0.6em] text-[#8B0000] mb-4 block font-bold">虔誠祈福 ‧ 感應神恩</span>
                    <h2 className="text-4xl md:text-6xl serif tracking-wide text-gray-900 leading-tight">年度祈福服務與聖物</h2>
                    <div className="h-1 w-24 bg-[#D4AF37] mt-6"></div>
                  </div>
                  <button onClick={fetchProducts} className="flex items-center space-x-3 text-[11px] uppercase tracking-widest text-gray-400 hover:text-[#8B0000] transition-colors border-b border-gray-100 pb-2">
                    <RefreshCw className={`w-3 h-3 ${isLoading ? 'animate-spin' : ''}`} />
                    <span>同步線上登記數據</span>
                  </button>
                </div>

                {isLoading ? (
                  <div className="flex flex-col items-center justify-center py-40 space-y-8">
                    <div className="relative">
                      <div className="w-16 h-16 border-4 border-[#D4AF37]/20 border-t-[#8B0000] rounded-full animate-spin"></div>
                      <Heart className="w-6 h-6 text-[#8B0000] absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
                    </div>
                    <span className="text-sm tracking-[0.4em] text-gray-400 uppercase font-bold serif">誠心感應中...</span>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-x-10 gap-y-20">
                    {products.map(product => (
                      <ProductCard 
                        key={product.product_id} 
                        product={product} 
                        onAddToCart={addToCart}
                        onViewDetail={(p) => { setSelectedProduct(p); setCurrentView('ProductDetail'); window.scrollTo(0, 0); }}
                      />
                    ))}
                  </div>
                )}
              </div>
            </section>
          </div>
        )}

        {currentView === 'Account' && user && (
          <div className="fade-in container mx-auto px-6 py-32 max-w-4xl">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-16 border-b-2 border-[#8B0000]/10 pb-12 gap-8">
              <div>
                <h2 className="text-5xl serif tracking-widest uppercase mb-4 text-[#8B0000]">信眾大德專區</h2>
                <div className="flex items-center space-x-4">
                   <span className="px-4 py-1.5 bg-[#8B0000] text-white text-[10px] uppercase tracking-widest font-bold border border-[#D4AF37]">福緣深厚</span>
                   <p className="text-xs tracking-[0.2em] text-gray-500 font-medium">感謝 {user.full_name} 大德長年護持</p>
                </div>
              </div>
              <button 
                onClick={handleLogout}
                className="flex items-center space-x-2 text-[11px] tracking-widest uppercase text-gray-400 hover:text-[#8B0000] transition-all border border-gray-100 px-8 py-4 rounded-sm"
              >
                <LogOut className="w-4 h-4" />
                <span>安全登出</span>
              </button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
              <div className="lg:col-span-1 space-y-2">
                <button className="w-full text-left px-6 py-5 bg-[#8B0000] text-white flex items-center justify-between group">
                  <span className="text-[12px] tracking-widest uppercase font-bold">信眾基本資料</span>
                  <ChevronRight className="w-4 h-4 text-[#D4AF37]" />
                </button>
                <button className="w-full text-left px-6 py-5 hover:bg-white border border-gray-50 flex items-center justify-between text-gray-500 transition-all">
                  <span className="text-[12px] tracking-widest uppercase font-bold">祈福登記紀錄</span>
                  <History className="w-4 h-4 opacity-30" />
                </button>
                <button className="w-full text-left px-6 py-5 hover:bg-white border border-gray-50 flex items-center justify-between text-gray-500 transition-all">
                  <span className="text-[12px] tracking-widest uppercase font-bold">慈悲功德回向</span>
                  <Heart className="w-4 h-4 opacity-30" />
                </button>
              </div>

              <div className="lg:col-span-2 space-y-12">
