                    <div className="space-y-2">
                      <span className="text-[10px] text-gray-400 uppercase tracking-widest block font-bold">聯絡信箱</span>
                      <p className="text-base font-bold text-gray-800">{user.email}</p>
                    </div>
                    <div className="space-y-2">
                      <span className="text-[10px] text-gray-400 uppercase tracking-widest block font-bold">聯絡電話</span>
                      <p className="text-base font-bold text-gray-800">{user.phone}</p>
                    </div>
                    <div className="space-y-2">
                      <span className="text-[10px] text-gray-400 uppercase tracking-widest block font-bold">生辰日期</span>
                      <p className="text-base font-bold text-gray-800">{user.birthday || '未設定'}</p>
                    </div>
                  </div>
                </div>

                <div className="p-12 bg-gradient-to-br from-[#8B0000] to-[#5a0000] text-white relative overflow-hidden shadow-2xl">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2"></div>
                  <div className="relative z-10">
                    <h4 className="text-xl serif tracking-widest mb-2 font-bold text-[#D4AF37]">本年度功德錄</h4>
                    <p className="text-sm opacity-90 leading-relaxed font-light mb-6">
                      您已累積登記 0 項祈福服務。功德無量，聖母護佑您家宅平安。
                    </p>
                    <button className="text-[10px] uppercase tracking-[0.3em] font-bold border-b border-[#D4AF37] pb-1">查看所有紀錄</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {currentView === 'Login' && (
          <div className="fade-in max-w-md mx-auto py-32 px-6">
            <div className="text-center mb-16">
              <div className="w-20 h-20 bg-[#8B0000]/5 rounded-full flex items-center justify-center mx-auto mb-8">
                <Landmark className="w-10 h-10 text-[#8B0000]" />
              </div>
              <h2 className="text-4xl serif mb-4 tracking-widest uppercase font-bold text-[#8B0000]">{authMode === 'Login' ? '信眾登入' : '開通線上帳戶'}</h2>
              <p className="text-xs tracking-[0.2em] text-gray-400 uppercase font-medium">
                {authMode === 'Login' ? '連結您的線上功德帳戶' : '加入南海慈寧宮線上祈福平台'}
              </p>
            </div>

            {successMsg && (
              <div className="mb-8 p-5 bg-green-50 text-green-800 flex items-center space-x-4 text-xs tracking-wider border-l-4 border-green-500">
                <CheckCircle2 className="w-5 h-5 flex-shrink-0" />
                <span>{successMsg}</span>
              </div>
            )}

            {error && (
              <div className="mb-8 p-5 bg-red-50 text-red-800 flex flex-col space-y-2 text-xs tracking-wider border-l-4 border-red-500">
                <div className="flex items-center space-x-4">
                  <AlertCircle className="w-5 h-5 flex-shrink-0" />
                  <span className="font-bold">{error.message}</span>
                </div>
              </div>
            )}

            <form onSubmit={handleAuthSubmit} className="space-y-8">
              {authMode === 'Register' && (
                <div className="space-y-8 animate-slide-up">
                  <div className="relative">
                    <label className="text-[9px] uppercase tracking-widest text-[#8B0000] absolute -top-4 left-0 font-bold">真實姓名</label>
                    <input 
                      required
                      type="text" 
                      placeholder="例：王小明 大德" 
