                  <div className="relative">
                    <label className="text-[9px] uppercase tracking-widest text-[#8B0000] absolute -top-4 left-0 font-bold">聯絡電話</label>
                    <input 
                      required
                      type="tel" 
                      placeholder="例：0912-345678" 
                      className="w-full border-b-2 border-orange-100 py-4 text-sm tracking-widest focus:border-[#D4AF37] outline-none transition-colors bg-transparent"
