                      onChange={(e) => setAuthFormData({...authFormData, phone: e.target.value})}
                    />
                  </div>
                  <div className="relative">
                    <label className="text-[9px] uppercase tracking-widest text-[#8B0000] absolute -top-4 left-0 font-bold">戶籍地址</label>
                    <input 
                      required
                      type="text" 
                      placeholder="用於填寫疏文祈福" 
                      className="w-full border-b-2 border-orange-100 py-4 text-sm tracking-widest focus:border-[#D4AF37] outline-none transition-colors bg-transparent"
                      value={authFormData.address}
                      onChange={(e) => setAuthFormData({...authFormData, address: e.target.value})}
                    />
                  </div>
                </div>
              )}

              <div className="relative">
                <label className="text-[9px] uppercase tracking-widest text-[#8B0000] absolute -top-4 left-0 font-bold">電子郵件</label>
                <input 
                  required
                  type="email" 
                  placeholder="EMAIL ADDRESS" 
                  className="w-full border-b-2 border-orange-100 py-4 text-sm tracking-widest focus:border-[#D4AF37] outline-none transition-colors bg-transparent"
                  value={authFormData.email}
                  onChange={(e) => setAuthFormData({...authFormData, email: e.target.value})}
                />
              </div>
              <div className="relative">
                <label className="text-[9px] uppercase tracking-widest text-[#8B0000] absolute -top-4 left-0 font-bold">登入密碼</label>
                <input 
                  required
                  type="password" 
                  placeholder="PASSWORD" 
                  className="w-full border-b-2 border-orange-100 py-4 text-sm tracking-widest focus:border-[#D4AF37] outline-none transition-colors bg-transparent"
                  value={authFormData.password}
                  onChange={(e) => setAuthFormData({...authFormData, password: e.target.value})}
                />
              </div>

              <button 
                type="submit"
                disabled={isSubmitting}
                className="w-full bg-[#8B0000] text-white py-6 mt-10 text-[13px] font-bold uppercase tracking-[0.4em] hover:bg-[#D4AF37] hover:text-black transition-all flex items-center justify-center space-x-4 disabled:bg-gray-200 border border-[#D4AF37] shadow-xl"
              >
                {isSubmitting ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    <span>正在連結雲端...</span>
                  </>
                ) : (
                  <span>{authMode === 'Login' ? '確認登入' : '立即註冊'}</span>
                )}
              </button>
            </form>

            <div className="mt-12 text-center">
              <button 
                onClick={() => {
                  setAuthMode(authMode === 'Login' ? 'Register' : 'Login');
                  setError(null);
                  setSuccessMsg(null);
                }}
                className="text-[11px] tracking-[0.2em] text-gray-500 uppercase hover:text-[#8B0000] transition-colors font-bold"
              >
                {authMode === 'Login' ? '尚未開通帳戶？點此加入' : '已有帳戶？點此登入'}
              </button>
            </div>
          </div>
        )}

        {currentView === 'ProductDetail' && selectedProduct && (
          <div className="fade-in container mx-auto px-6 py-32">
            <button onClick={() => setCurrentView('Home')} className="flex items-center space-x-2 text-[11px] uppercase tracking-[0.2em] text-[#8B0000] hover:text-[#D4AF37] mb-16 group font-bold">
              <ArrowLeft className="w-5 h-5 transition-transform group-hover:-translate-x-1" />
              <span>返回祈福大殿</span>
            </button>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-20 lg:items-start">
              <div className="aspect-[4/5] bg-white p-2 border border-orange-50 shadow-2xl overflow-hidden rounded-sm">
                <img src={selectedProduct.image_url} className="w-full h-full object-cover rounded-sm" alt={selectedProduct.name} />
              </div>
              <div className="flex flex-col justify-center">
                <span className="text-[12px] uppercase tracking-[0.5em] text-[#8B0000] font-bold mb-6 block border-l-4 border-[#D4AF37] pl-4">{selectedProduct.category}</span>
                <h1 className="text-5xl md:text-6xl serif mb-8 tracking-wide leading-tight font-bold text-gray-900">{selectedProduct.name}</h1>
                <div className="flex items-baseline space-x-6 mb-10 border-b border-orange-50 pb-10">
                  <span className="text-3xl font-bold tracking-widest text-[#8B0000]">結緣價 NT$ {selectedProduct.price.toLocaleString()}</span>
                </div>
                <div className="space-y-8 mb-16">
                  <div className="space-y-4">
                    <h5 className="text-sm font-bold tracking-widest text-gray-400 uppercase">服務介紹</h5>
                    <p className="text-gray-700 leading-loose font-medium text-lg serif">{selectedProduct.description}</p>
                  </div>
                  <div className="space-y-4">
                    <h5 className="text-sm font-bold tracking-widest text-gray-400 uppercase">詳細內容</h5>
                    <p className="text-gray-600 leading-loose text-base serif">{selectedProduct.detail_content}</p>
                  </div>
                </div>
                <div className="space-y-6">
                  <div className="flex items-center justify-between text-[11px] uppercase tracking-widest text-gray-400 mb-2 font-bold">
                    <span>規格說明</span>
                    <span className="text-[#8B0000]">{selectedProduct.spec}</span>
                  </div>
                  <button onClick={() => addToCart(selectedProduct)} className="w-full bg-[#8B0000] text-white py-8 text-[13px] uppercase tracking-[0.4em] font-bold hover:bg-[#D4AF37] hover:text-black transition-all border border-[#D4AF37] shadow-2xl">
                    立即加入祈福清單
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Cart Sidebar (Blessing List) */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[100] overflow-hidden">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-[4px]" onClick={() => setIsCartOpen(false)}></div>
          <div className="absolute top-0 right-0 bottom-0 w-full max-w-md bg-[#fffdf9] shadow-2xl flex flex-col transform transition-transform duration-700 ease-in-out border-l-4 border-[#D4AF37]">
            <div className="px-10 py-12 flex items-center justify-between border-b border-orange-100 bg-[#8B0000] text-white">
              <h2 className="text-2xl serif tracking-widest uppercase font-bold">祈福清單 ({cartCount})</h2>
              <button onClick={() => setIsCartOpen(false)} className="p-2 hover:text-[#D4AF37] transition-colors"><X className="w-6 h-6" /></button>
            </div>
            <div className="flex-1 overflow-y-auto px-10 py-10 space-y-12 bg-pattern">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center space-y-8">
                  <Heart className="w-20 h-20 text-orange-100 stroke-[1px]" />
                  <p className="text-xs tracking-[0.4em] text-gray-300 uppercase font-bold serif">清單中尚無登記項目</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.product_id} className="flex space-x-8 group">
                    <div className="w-24 h-32 bg-white p-1 border border-orange-50 shadow-md flex-shrink-0"><img src={item.image_url} className="w-full h-full object-cover" /></div>
                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div>
                        <div className="flex justify-between items-start mb-3">
                          <h4 className="text-lg font-bold tracking-wide text-gray-900 leading-snug serif">{item.name}</h4>
                          <button onClick={() => removeFromCart(item.product_id)} className="text-gray-300 hover:text-[#8B0000] transition-colors"><X className="w-5 h-5" /></button>
                        </div>
                        <span className="text-[10px] uppercase tracking-widest text-[#8B0000] font-bold border border-[#8B0000]/20 px-2 py-0.5">{item.category}</span>
                      </div>
                      <div className="flex items-center justify-between mt-6">
                        <div className="flex items-center border border-orange-100 rounded-sm bg-white overflow-hidden">
                          <button onClick={() => updateQuantity(item.product_id, -1)} className="px-4 py-2 text-[#8B0000] hover:bg-orange-50 transition-colors">-</button>
                          <span className="px-3 text-xs font-bold text-gray-800">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.product_id, 1)} className="px-4 py-2 text-[#8B0000] hover:bg-orange-50 transition-colors">+</button>
                        </div>
                        <span className="text-base font-bold tracking-widest text-[#8B0000]">NT$ {(item.price * item.quantity).toLocaleString()}</span>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
            {cart.length > 0 && (
              <div className="px-10 py-12 bg-white border-t-2 border-[#D4AF37]">
                <div className="flex items-center justify-between mb-10">
                  <span className="text-[11px] tracking-[0.4em] font-bold uppercase text-gray-400">總計功德金</span>
                  <span className="text-3xl serif font-bold text-[#8B0000]">NT$ {cartTotal.toLocaleString()}</span>
                </div>
                <button className="w-full bg-[#8B0000] text-white py-7 text-[13px] uppercase tracking-[0.5em] font-bold hover:bg-black transition-all flex items-center justify-center space-x-4 shadow-xl border border-[#D4AF37]">
                  <span>前往線上登記結緣</span>
                  <ChevronRight className="w-5 h-5" />
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import ProductCard from './components/ProductCard';
import { Product, CartItem, Member } from './types';
// Added Landmark to the lucide-react import list
import { X, ChevronRight, ShoppingBag, ArrowLeft, Loader2, AlertCircle, RefreshCw, CheckCircle2, LogOut, User as UserIcon, Settings, History, CreditCard, Heart, Landmark } from 'lucide-react';

type View = 'Home' | 'ProductDetail' | 'Cart' | 'Login' | 'Account';
type AuthMode = 'Login' | 'Register';

const GAS_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbzBphMCZ8eQ3ye4RA3okuKz92qfZ8UwPvrfs-bd2TnEgSFvrkE6-r8dS9ONDMOOQhAm/exec';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('Home');
  const [authMode, setAuthMode] = useState<AuthMode>('Login');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<{ message: string; details?: string } | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [user, setUser] = useState<Partial<Member> | null>(null);

  const [authFormData, setAuthFormData] = useState({
    email: '',
    password: '',
    full_name: '',
    phone: '',
    address: '',
    gender: '',
    birthday: '',
  });

  const fetchProducts = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=getProducts&timestamp=${Date.now()}`);
      const data = await response.json();
      if (data.error) throw new Error(data.error);
      setProducts(Array.isArray(data) ? data : []);
    } catch (err: any) {
      console.error('[APP_ERROR]', err);
      // Fallback to local mock data if GAS fails
      const { MOCK_PRODUCTS } = await import('./data/mockData');
      setProducts(MOCK_PRODUCTS);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchProducts(); }, [fetchProducts]);

  useEffect(() => {
    const savedCart = localStorage.getItem('cining_cart');
    if (savedCart) try { setCart(JSON.parse(savedCart)); } catch (e) {}
    const savedUser = sessionStorage.getItem('cining_user');
    if (savedUser) try { setUser(JSON.parse(savedUser)); } catch (e) {}
  }, []);

  useEffect(() => { localStorage.setItem('cining_cart', JSON.stringify(cart)); }, [cart]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product_id === product.product_id);
      if (existing) return prev.map(item => item.product_id === product.product_id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (productId: string) => setCart(prev => prev.filter(item => item.product_id !== productId));
  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => item.product_id === productId ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item));
  };

  const handleLogout = () => {
    setUser(null);
    sessionStorage.removeItem('cining_user');
    setCurrentView('Home');
  };

  const handleAuthSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    setSuccessMsg(null);

    const payload = {
      action: authMode === 'Register' ? 'register' : 'login',
      ...authFormData
    };

    try {
      const response = await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(payload),
      });
      const result = await response.json();
      if (result.error) throw new Error(result.error);

      if (authMode === 'Register') {
        setSuccessMsg('帳號已成功建立。現在您可以登入了。');
        setAuthMode('Login');
        setAuthFormData(prev => ({ ...prev, password: '' }));
      } else {
        if (result.member) {
          setUser(result.member);
          sessionStorage.setItem('cining_user', JSON.stringify(result.member));
          setSuccessMsg('驗證成功，歡迎回到南海慈寧宮。');
          setTimeout(() => {
            setCurrentView('Home');
            setSuccessMsg(null);
          }, 1500);
        }
      }
    } catch (err: any) {
      setError({ message: err.message, details: '請確認帳號密碼是否正確。' });
    } finally {
      setIsSubmitting(false);
    }
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen bg-[#fffdf9]">
      <Header 
        cartCount={cartCount} 
        onCartClick={() => setIsCartOpen(true)}
        onUserClick={() => user ? setCurrentView('Account') : setCurrentView('Login')}
        onHomeClick={() => { setCurrentView('Home'); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
        user={user}
      />

      <main className="pt-0">
        {currentView === 'Home' && (
          <div className="fade-in">
            <Hero />
            <section className="py-24 bg-white border-y border-orange-100 relative overflow-hidden">
               {/* Decorative background element */}
              <div className="absolute top-0 right-0 w-64 h-64 bg-[#8B0000]/5 rounded-full -translate-y-1/2 translate-x-1/2"></div>

              <div className="container mx-auto px-6 relative z-10">
                <div className="flex flex-col md:flex-row md:items-end justify-between mb-20 gap-8">
                  <div className="max-w-xl">
                    <span className="text-[11px] uppercase tracking-[0.6em] text-[#8B0000] mb-4 block font-bold">虔誠祈福 ‧ 感應神恩</span>
                    <h2 className="text-4xl md:text-6xl serif tracking-wide text-gray-900 leading-tight">年度祈福服務與聖物</h2>
                    <div className="h-1 w-24 bg-[#D4AF37] mt-6"></div>
                  </div>
                  <button onClick={fetchProducts} className="flex items-center space-x-3 text-[11px] uppercase tracking-widest text-gray-400 hover:text-[#8B0000] transition-colors border-b border-gray-100 pb-2">
                    <RefreshCw className={`w-3 h-3 ${isLoading ? 'animate-spin' : ''}`} />
                    <span>同步線上登記數據</span>
                  </button>
                </div>

                {isLoading ? (
                  <div className="flex flex-col items-center justify-center py-40 space-y-8">
                    <div className="relative">
                      <div className="w-16 h-16 border-4 border-[#D4AF37]/20 border-t-[#8B0000] rounded-full animate-spin"></div>
                      <Heart className="w-6 h-6 text-[#8B0000] absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
                    </div>
                    <span className="text-sm tracking-[0.4em] text-gray-400 uppercase font-bold serif">誠心感應中...</span>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-x-10 gap-y-20">
                    {products.map(product => (
                      <ProductCard 
                        key={product.product_id} 
                        product={product} 
                        onAddToCart={addToCart}
                        onViewDetail={(p) => { setSelectedProduct(p); setCurrentView('ProductDetail'); window.scrollTo(0, 0); }}
                      />
                    ))}
                  </div>
                )}
              </div>
            </section>
          </div>
        )}

        {currentView === 'Account' && user && (
          <div className="fade-in container mx-auto px-6 py-32 max-w-4xl">
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-16 border-b-2 border-[#8B0000]/10 pb-12 gap-8">
              <div>
                <h2 className="text-5xl serif tracking-widest uppercase mb-4 text-[#8B0000]">信眾大德專區</h2>
                <div className="flex items-center space-x-4">
