                    <div className="group space-y-8 text-center md:mt-24">
                       <div className="relative aspect-[3/4] overflow-hidden ornament-border">
                          <img 
                            src="https://images.unsplash.com/photo-1614104030927-507f7f3d4c1e?auto=format&fit=crop&q=80&w=1000" 
                            className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110"
                            alt="南海慈寧聖母"
                          />
                          <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex items-end justify-center p-12">
                             <h3 className="text-3xl serif-bold text-[#D4AF37]">南海慈寧聖母</h3>
                          </div>
                       </div>
                       <p className="text-gray-400 leading-relaxed italic max-w-sm mx-auto serif">「聖母慈光，護國佑民」</p>
                    </div>
                 </div>
               </div>
            </section>

            {/* Core Rituals Section */}
            <section className="py-40 bg-white">
              <div className="container mx-auto px-6">
                <div className="flex flex-col md:flex-row justify-between items-end mb-32 border-b-2 border-[#F5F5F5] pb-16">
                  <div className="space-y-4">
                    <span className="text-[#8B0000] text-[11px] tracking-[0.6em] font-bold uppercase">Ritual Registrations</span>
                    <h2 className="text-5xl md:text-6xl serif-bold text-[#1A1A1A]">法務登記 / 功德項目</h2>
                  </div>
                  <button onClick={fetchProducts} className="text-xs uppercase tracking-widest text-gray-400 hover:text-[#8B0000] flex items-center gap-3 mt-8 md:mt-0">
                    <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} /> 同步廟方數據
                  </button>
                </div>

                {isLoading ? (
                  <div className="py-60 flex flex-col items-center justify-center space-y-8">
                    <Loader2 className="w-12 h-12 animate-spin text-[#8B0000]" />
                    <p className="calligraphy text-2xl text-gray-400">誠心感應中...</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12">
                    {products.map(product => (
                      <ProductCard 
                        key={product.product_id} 
                        product={product} 
                        onAddToCart={addToCart}
                        onViewDetail={(p) => { setSelectedProduct(p); setCurrentView('ProductDetail'); window.scrollTo(0, 0); }}
                      />
                    ))}
                  </div>
                )}
              </div>
            </section>
          </div>
        )}

        {currentView === 'Checkout' && (
          <div className="fade-in container mx-auto px-6 py-40 max-w-5xl">
            <button onClick={() => setCurrentView('Home')} className="flex items-center space-x-3 text-[11px] uppercase tracking-[0.2em] text-[#8B0000] mb-16 font-bold">
              <ArrowLeft className="w-5 h-5" /> <span>取消並返回大殿</span>
            </button>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-20">
              <div className="lg:col-span-2 space-y-16">
                 <div className="space-y-4">
                    <h2 className="text-5xl serif-bold text-[#8B0000]">法務登記資料確認</h2>
                    <p className="text-gray-500 serif">請填寫大德資訊，我們將依此為您填寫疏文並進行儀式。</p>
                 </div>

                 <div className="bg-white p-12 border border-orange-50 shadow-xl ornament-border">
                    <h3 className="text-2xl serif-bold mb-10 flex items-center gap-4 text-[#1A1A1A]">
                       <ShieldCheck className="w-7 h-7 text-[#D4AF37]" /> 登記人資訊
                    </h3>
                    <div className="space-y-10">
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                          <div>
                            <label className="text-[10px] uppercase tracking-widest text-gray-400 block mb-3 font-bold">登記者姓名</label>
                            <p className="text-xl font-bold border-b-2 border-orange-50 pb-4">{user?.full_name}</p>
                          </div>
                          <div>
                            <label className="text-[10px] uppercase tracking-widest text-gray-400 block mb-3 font-bold">聯絡電話</label>
                            <p className="text-xl font-bold border-b-2 border-orange-50 pb-4">{user?.phone}</p>
                          </div>
                       </div>
                       <div>
                          <label className="text-[10px] uppercase tracking-widest text-gray-400 block mb-3 font-bold">祈福疏文地址 (或聖物寄送地址)</label>
                          <input 
                            type="text"
                            className="w-full border-b-2 border-[#D4AF37] py-6 text-xl outline-none focus:bg-orange-50 transition-all bg-transparent serif"
                            value={shippingAddr}
                            onChange={(e) => setShippingAddr(e.target.value)}
                            placeholder="請填寫詳細居住地址"
                          />
                       </div>
                    </div>
                 </div>
              </div>

              <div className="lg:col-span-1">
                 <div className="bg-[#1A1A1A] text-white p-10 border-t-8 border-[#8B0000] shadow-2xl sticky top-40">
                    <h3 className="text-2xl serif-bold mb-10 text-[#D4AF37]">項目清單</h3>
                    <div className="space-y-8 mb-12">
                       {cart.map(item => (
                         <div key={item.product_id} className="flex justify-between items-center text-sm">
                            <span className="opacity-70">{item.name} ({item.quantity})</span>
                            <span className="font-bold">NT$ {(item.price * item.quantity).toLocaleString()}</span>
                         </div>
                       ))}
                       <div className="pt-8 border-t border-white/10 flex justify-between items-center">
                          <span className="text-xs uppercase tracking-[0.3em]">功德金總計</span>
                          <span className="text-3xl serif-bold text-[#D4AF37]">NT$ {cartTotal.toLocaleString()}</span>
                       </div>
                    </div>

                    {error && (
                       <div className="mb-8 p-6 bg-red-900/40 border border-red-500 flex gap-4 text-xs text-red-200">
                          <AlertCircle className="w-5 h-5 flex-shrink-0" />
                          <span>{error.message}</span>
                       </div>
                    )}

                    <button 
                      onClick={submitOrder}
                      disabled={isSubmitting || cart.length === 0}
                      className="w-full bg-[#8B0000] text-white py-8 text-lg font-bold uppercase tracking-[0.5em] hover:bg-[#B8860B] transition-all flex items-center justify-center gap-4 border border-[#D4AF37] shadow-xl"
                    >
                      {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin" /> : <Send className="w-6 h-6" />}
                      <span>確認送出登記</span>
                    </button>
                    <p className="text-[10px] text-center mt-8 text-gray-500 leading-loose italic">「誠心所向，金石為開。登記完成後將由本宮道長擇吉日為您稟告聖母。」</p>
                 </div>
              </div>
            </div>
          </div>
        )}

        {/* ... Login/Account views remain unchanged ... */}
        {currentView === 'Login' && (
          <div className="fade-in max-w-md mx-auto py-40 px-6">
             <div className="text-center mb-16">
              <div className="w-24 h-24 bg-[#8B0000] text-[#D4AF37] rounded-full flex items-center justify-center mx-auto mb-10 shadow-xl border-4 border-[#D4AF37]"><Landmark className="w-12 h-12" /></div>
              <h2 className="text-5xl serif-bold mb-6 tracking-widest uppercase text-[#1A1A1A]">{authMode === 'Login' ? '信眾登入' : '開通帳戶'}</h2>
              <p className="calligraphy text-2xl text-gray-400">登入大殿 ‧ 共霑法喜</p>
            </div>
            {error && <div className="mb-10 p-6 bg-red-50 text-red-800 text-sm border-l-4 border-red-500 flex items-center gap-4"><AlertCircle className="w-6 h-6" /> {error.message}</div>}
            <form onSubmit={handleAuthSubmit} className="space-y-12">
               {authMode === 'Register' && (
                 <input 
                  required type="text" placeholder="大德姓名" className="w-full border-b-2 border-orange-100 py-6 outline-none focus:border-[#8B0000] text-lg serif bg-transparent"
                  onChange={(e) => setAuthFormData({...authFormData, full_name: e.target.value})}
                />
               )}
               <input 
                required type="email" placeholder="電子郵件" className="w-full border-b-2 border-orange-100 py-6 outline-none focus:border-[#8B0000] text-lg serif bg-transparent"
                onChange={(e) => setAuthFormData({...authFormData, email: e.target.value})}
              />
               <input 
                required type="password" placeholder="登入密碼" className="w-full border-b-2 border-orange-100 py-6 outline-none focus:border-[#8B0000] text-lg serif bg-transparent"
                onChange={(e) => setAuthFormData({...authFormData, password: e.target.value})}
              />
               <button type="submit" disabled={isSubmitting} className="w-full bg-[#8B0000] text-white py-8 text-xl font-bold uppercase tracking-[0.5em] border border-[#D4AF37] shadow-xl">
                 {isSubmitting ? '請稍候...' : authMode === 'Login' ? '登入大殿' : '立即開通'}
               </button>
            </form>
            <button onClick={() => setAuthMode(authMode === 'Login' ? 'Register' : 'Login')} className="w-full mt-12 text-[11px] text-gray-400 font-bold uppercase tracking-[0.3em] hover:text-[#8B0000] transition-colors">
              {authMode === 'Login' ? '尚未開通信眾帳戶？點此加入' : '已有帳戶？點此登入'}
            </button>
          </div>
        )}

        {currentView === 'ProductDetail' && selectedProduct && (
          <div className="fade-in container mx-auto px-6 py-40">
            <button onClick={() => setCurrentView('Home')} className="flex items-center space-x-3 text-[11px] uppercase tracking-[0.2em] text-[#8B0000] mb-20 font-bold">
              <ArrowLeft className="w-5 h-5" /> <span>返回宮廟首頁</span>
            </button>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-32">
              <div className="ornament-border bg-white p-4 shadow-2xl">
                <img src={selectedProduct.image_url} className="w-full h-full object-cover" alt={selectedProduct.name} />
              </div>
              <div className="flex flex-col justify-center space-y-12">
                <div>
                  <span className="text-sm tracking-[0.8em] text-[#8B0000] font-bold mb-6 block uppercase">{selectedProduct.category}</span>
                  <h1 className="text-6xl serif-bold text-[#1A1A1A] mb-8">{selectedProduct.name}</h1>
                  <p className="text-4xl font-bold text-[#8B0000] serif">功德金 NT$ {selectedProduct.price.toLocaleString()}</p>
                </div>

                <div className="space-y-6">
                   <h4 className="text-sm font-bold tracking-widest text-gray-400 uppercase">項目描述</h4>
                   <p className="text-xl text-gray-700 leading-loose serif">{selectedProduct.description}</p>
                </div>

                <div className="space-y-6 border-t-2 border-orange-50 pt-12">
                  <h4 className="text-sm font-bold tracking-widest text-gray-400 uppercase">登記細則</h4>
                  <p className="text-gray-600 leading-loose serif">{selectedProduct.detail_content}</p>
                </div>

                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-[#8B0000] text-white py-8 text-xl font-bold tracking-[0.5em] border border-[#D4AF37] shadow-2xl hover:bg-[#B8860B] transition-all">
                  加入報名清單
                </button>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Cart Sidebar */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[100] overflow-hidden">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="absolute top-0 right-0 bottom-0 w-full max-w-lg bg-[#FCF9F2] shadow-2xl flex flex-col border-l-8 border-[#8B0000] cloud-pattern">
            <div className="px-12 py-16 flex items-center justify-between bg-[#1A1A1A] text-[#D4AF37] border-b-2 border-[#D4AF37]">
              <h2 className="text-3xl serif-bold tracking-widest uppercase">法務報名清單</h2>
              <button onClick={() => setIsCartOpen(false)} className="hover:rotate-90 transition-transform"><X className="w-8 h-8" /></button>
            </div>
            <div className="flex-1 overflow-y-auto px-12 py-12 space-y-12">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center space-y-8 opacity-20">
                   <Landmark className="w-32 h-32" />
                   <p className="calligraphy text-3xl">清單虛位以待</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.product_id} className="flex space-x-8 border-b border-orange-100 pb-12">
                    <div className="w-24 h-32 bg-white border border-orange-50 p-1 shadow-md"><img src={item.image_url} className="w-full h-full object-cover" /></div>
                    <div className="flex-1 flex flex-col justify-between">
                      <div className="flex justify-between items-start">
                        <h4 className="text-xl serif-bold text-[#1A1A1A]">{item.name}</h4>
                        <button onClick={() => removeFromCart(item.product_id)}><X className="w-5 h-5 text-gray-300 hover:text-[#8B0000]" /></button>
                      </div>
                      <div className="flex items-center justify-between">
                        <div className="flex items-center border border-[#D4AF37] bg-white">
                          <button onClick={() => updateQuantity(item.product_id, -1)} className="px-4 py-2 text-[#8B0000]">-</button>
                          <span className="px-4 text-sm font-bold">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.product_id, 1)} className="px-4 py-2 text-[#8B0000]">+</button>
                        </div>
                        <span className="text-lg font-bold text-[#8B0000]">NT$ {(item.price * item.quantity).toLocaleString()}</span>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
            {cart.length > 0 && (
              <div className="px-12 py-16 bg-white border-t-4 border-[#D4AF37] shadow-[0_-20px_40px_rgba(0,0,0,0.05)]">
                <div className="flex justify-between items-center mb-12">
                  <span className="text-gray-400 font-bold uppercase tracking-widest text-sm">結緣總金額</span>
                  <span className="text-4xl serif-bold text-[#8B0000]">NT$ {cartTotal.toLocaleString()}</span>
                </div>
                <button onClick={startCheckout} className="w-full bg-[#8B0000] text-white py-8 text-xl font-bold tracking-[0.5em] shadow-xl hover:bg-[#1A1A1A] transition-all border border-[#D4AF37]">
                  確認並填寫資料
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import ProductCard from './components/ProductCard';
import { Product, CartItem, Member } from './types';
import { X, ChevronRight, ShoppingBag, ArrowLeft, Loader2, AlertCircle, RefreshCw, CheckCircle2, LogOut, User as UserIcon, Settings, History, CreditCard, Heart, Landmark, MapPin, Sparkles, BookOpen, Star, Send, ShieldCheck, Moon, Sun, HeartHandshake, Compass, Zap } from 'lucide-react';

type View = 'Home' | 'ProductDetail' | 'Cart' | 'Login' | 'Account' | 'Checkout' | 'History';
type AuthMode = 'Login' | 'Register';

const GAS_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbxD6QwijcuVb6l3RSB1XGE0hA9cjXUg3us_tmtVIBReeL2ffAaS_ZJKDFKMt1aCkJ0a/exec';

const QUICK_ACCESS_ITEMS = [
  { id: 1, title: '點燈祈福', imgId: '1gpME6-MqIAWRp7z9Oy95vLUyGdtWiIt6' },
  { id: 2, title: '油香喜添', imgId: '1s_N9r_7kx0dygts1HDdUwOVXHSVcC5R_' },
  { id: 3, title: '祈安燈籠', imgId: '1juMctdxwkk91ldfC_PUu1SYtP-qvEPqH' },
  { id: 4, title: '線上求籤', imgId: '1WtFQQT2Mq3jX-Iq7I65P046EbE1N0g1C' },
  { id: 5, title: '靈籤解籤', imgId: '1rcm_LaIAMYbZFEhHu4L9gTRtfvB4B64B' },
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('Home');
  const [authMode, setAuthMode] = useState<AuthMode>('Login');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<{ message: string; details?: string } | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [user, setUser] = useState<Partial<Member> | null>(null);

  const introRef = useRef<HTMLDivElement>(null);

  const [authFormData, setAuthFormData] = useState({
    email: '',
    password: '',
    full_name: '',
    phone: '',
    address: '',
    gender: '',
    birthday: '',
  });

  const [shippingAddr, setShippingAddr] = useState('');

  const fetchProducts = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=getProducts&timestamp=${Date.now()}`);
      const data = await response.json();
      if (data.error) throw new Error(data.error);
      setProducts(Array.isArray(data) ? data : []);
    } catch (err: any) {
      console.error('[APP_ERROR]', err);
      const { MOCK_PRODUCTS } = await import('./data/mockData');
      setProducts(MOCK_PRODUCTS);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchProducts(); }, [fetchProducts]);

  useEffect(() => {
    const savedCart = localStorage.getItem('cining_cart');
    if (savedCart) try { setCart(JSON.parse(savedCart)); } catch (e) {}
    const savedUser = sessionStorage.getItem('cining_user');
    if (savedUser) try { 
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser); 
      setShippingAddr(parsedUser.address || '');
    } catch (e) {}
  }, []);

  useEffect(() => { localStorage.setItem('cining_cart', JSON.stringify(cart)); }, [cart]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product_id === product.product_id);
      if (existing) return prev.map(item => item.product_id === product.product_id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (productId: string) => setCart(prev => prev.filter(item => item.product_id !== productId));
  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => item.product_id === productId ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item));
  };

  const handleLogout = () => {
    setUser(null);
    sessionStorage.removeItem('cining_user');
    setCurrentView('Home');
  };

  const startCheckout = () => {
    if (!user) {
      setIsCartOpen(false);
      setCurrentView('Login');
      setError({ message: '大德，請先登入帳戶', details: '登入後即可進行線上法務登記。' });
      return;
    }
    setIsCartOpen(false);
    setCurrentView('Checkout');
    window.scrollTo(0, 0);
  };

  const submitOrder = async () => {
    if (!user || cart.length === 0) return;
    setIsSubmitting(true);
    setError(null);

    const orderData = {
      action: 'createOrder',
      m_id: user.member_id,
      items: cart.map(item => ({ product_id: item.product_id, name: item.name, quantity: item.quantity, price: item.price })),
      o_total: cartTotal,
      o_shipping_addr: shippingAddr
    };

    try {
      const response = await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(orderData),
      });
      const result = await response.json();
      if (result.error) throw new Error(result.error);

      setSuccessMsg(`登記成功！感謝您的虔誠護持。`);
      setCart([]);
      setTimeout(() => {
        setCurrentView('Home');
        setSuccessMsg(null);
      }, 3000);
    } catch (err: any) {
      setError({ message: '登記失敗', details: err.message });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleAuthSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    const payload = {
      action: authMode === 'Register' ? 'register' : 'login',
      ...authFormData
    };

    try {
      const response = await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(payload),
      });
      const result = await response.json();
      if (result.error) throw new Error(result.error);

      if (authMode === 'Register') {
        setSuccessMsg('帳號已成功開通。請登入。');
        setAuthMode('Login');
      } else {
        if (result.member) {
          setUser(result.member);
          setShippingAddr(result.member.address || '');
          sessionStorage.setItem('cining_user', JSON.stringify(result.member));
          setCurrentView('Home');
        }
      }
    } catch (err: any) {
      setError({ message: err.message });
    } finally {
      setIsSubmitting(false);
    }
  };

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen">
      <Header 
        cartCount={cartCount} 
        onCartClick={() => setIsCartOpen(true)}
        onUserClick={() => user ? setCurrentView('Account') : setCurrentView('Login')}
        onHomeClick={() => { setCurrentView('Home'); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
        onIntroClick={() => { setCurrentView('Home'); setTimeout(() => introRef.current?.scrollIntoView({ behavior: 'smooth' }), 100); }}
        user={user}
      />

      <main>
        {currentView === 'Home' && (
          <div className="fade-in">
            <Hero />

            {/* 線上服務快捷入口 (Quick Access) */}
            <section className="py-24 bg-white relative">
              <div className="container mx-auto px-6">
                <div className="flex flex-col items-center mb-20 text-center">
                   <h2 className="text-3xl md:text-5xl serif-bold text-[#1A1A1A] mb-6">線上服務快捷入口</h2>
                   <div className="h-1 w-32 bg-[#003366]"></div>
                   <p className="mt-8 text-gray-500 serif tracking-widest">點點誠心，透過數位連結與聖母感應</p>
                </div>

                {/* 3+2 Layout Strategy */}
                <div className="flex flex-col space-y-16">
                   {/* Top Row: 3 Items */}
                   <div className="grid grid-cols-1 sm:grid-cols-3 gap-12 max-w-6xl mx-auto w-full">
