                {link.name}
              </button>
            ))}
            {user && (
              <div className="pt-4 text-[#D4AF37] text-sm">
                歡迎，{user.full_name} 大德
              </div>
            )}
          </nav>
        </div>
      )}
    </header>
  );
};

export default Header;

