import React, { useState, useEffect } from 'react';
import { Menu, X, Landmark } from 'lucide-react';

interface HeaderProps {
  onHomeClick: () => void;
  onIntroClick: () => void;
  onGodsClick: () => void;
  onPilgrimageClick: () => void;
}

const Header: React.FC<HeaderProps> = ({ onHomeClick, onIntroClick, onGodsClick, onPilgrimageClick }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: '宮廟沿革', action: onIntroClick },
    { name: '祀奉神尊', action: onGodsClick },
    { name: '參拜動線', action: onPilgrimageClick },
  ];

  const handleNavClick = (action: () => void) => {
    action();
    setIsMobileMenuOpen(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <header className={`fixed top-0 left-0 right-0 z-[100] transition-all duration-300 ${
      isScrolled || isMobileMenuOpen ? 'bg-white shadow-lg py-4 border-b border-gray-100' : 'bg-transparent py-6'
    }`}>
      <div className="container mx-auto px-6 flex items-center justify-between">
        <button className="lg:hidden p-2 text-[#B22222]" onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X className="w-8 h-8" /> : <Menu className="w-8 h-8" />}
        </button>

        <nav className="hidden lg:flex items-center space-x-10 text-[14px] font-black tracking-widest text-[#333333]">
          {navLinks.slice(0, 2).map(link => (
            <button key={link.name} onClick={() => handleNavClick(link.action)} className="hover:text-[#B22222] transition-colors">{link.name}</button>
          ))}
        </nav>

        <button onClick={() => handleNavClick(onHomeClick)} className="flex flex-col items-center group">
          <div className="flex items-center gap-2">
            <Landmark className="w-6 h-6 text-[#B22222]" />
            <h1 className="text-2xl font-black tracking-[0.3em] serif-title text-[#B22222]">南海慈寧宮</h1>
          </div>
        </button>

        <nav className="hidden lg:flex items-center space-x-10 text-[14px] font-black tracking-widest text-[#333333]">
          {navLinks.slice(2).map(link => (
            <button key={link.name} onClick={() => handleNavClick(link.action)} className="hover:text-[#B22222] transition-colors">{link.name}</button>
          ))}
        </nav>
        <div className="w-8 lg:hidden"></div>
      </div>

      {isMobileMenuOpen && (
        <div className="lg:hidden absolute top-full left-0 right-0 bg-white h-screen border-t border-gray-100">
          <nav className="flex flex-col p-10 space-y-8">
            {navLinks.map(link => (
              <button key={link.name} onClick={() => handleNavClick(link.action)} className="text-3xl font-black text-[#B22222] serif-title tracking-widest text-center border-b border-gray-50 pb-6">
                {link.name}
              </button>
            ))}
          </nav>
        </div>
      )}
    </header>
  );
};

export default Header;

/**
 * 南海慈寧宮 - Google Apps Script 後端系統 (修復版)
 */

const PRODUCT_SHEET_ID = '1AxzphT6sT3CYTwFDlhFftfZhLJh_OCfjCmxfF9I918U';
const LIGHTING_SHEET_ID = '1ji7dhR6UqK1Xatpiu-fRuLEc67NP6gR_0cQvFr1wMac';
const INQUIRY_SHEET_ID = '1pbB2kXGjWt9PU8kbW0qiNDnkQ4bpIFK45fKjZOgc87A';

function doPost(e) {
  try {
    const params = JSON.parse(e.postData.contents);
    if (params.action === 'submitCustomForm') return handleCustomFormSubmission(params);
    return createJsonResponse({ error: '未知操作' });
  } catch (err) {
    return createJsonResponse({ error: '系統錯誤', details: err.toString() });
  }
}

function handleCustomFormSubmission(data) {
  try {
    const ssId = data.formType === '點燈報名' ? LIGHTING_SHEET_ID : INQUIRY_SHEET_ID;
    const ss = SpreadsheetApp.openById(ssId);
    const sheet = ss.getSheets()[0];
    const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];

    const newRow = headers.map(header => {
      const h = header.toString().trim();
      // 指令優化：加入防空值檢測
      const getValue = (val) => (val === undefined || val === null ? "" : val);

      if (h === '提交時間') return getValue(data.timestamp);
      if (h === '姓名') return getValue(data.name);
      if (h === '電話') return getValue(data.phone);
      if (h === '生日') return getValue(data.birthday);
      if (h === '性別') return getValue(data.gender);
      if (h === '地址') return getValue(data.address);
      if (h === '項目' || h === '類別') return getValue(data.item);
      if (h === '說明' || h === '事由') return getValue(data.reason);
      return "";
    });

    sheet.appendRow(newRow);
    return createJsonResponse({ success: true });
  } catch (e) {
    return createJsonResponse({ error: '寫入失敗', details: e.toString() });
  }
}

function doGet(e) {
  try {
    const ss = SpreadsheetApp.openById(PRODUCT_SHEET_ID);
    const sheet = ss.getSheets()[0];
    const data = sheet.getDataRange().getValues();
    const headers = data[0].map(h => h.toString().toLowerCase().trim());
    const products = data.slice(1).map(row => {
      let obj = {};
      headers.forEach((h, i) => { 
        // 指令優化：防止空值導致解析錯誤
        obj[h] = row[i] !== undefined && row[i] !== null ? row[i] : ""; 
      });
      return obj;
    }).filter(p => p.status === 'Active');
    return createJsonResponse(products);
  } catch (err) {
    return createJsonResponse({ error: '讀取失敗', details: err.toString() });
  }
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
}

