const PRODUCT_SHEET_ID = '1AxzphT6sT3CYTwFDlhFftfZhLJh_OCfjCmxfF9I918U';
const LIGHTING_SHEET_ID = '1ji7dhR6UqK1Xatpiu-fRuLEc67NP6gR_0cQvFr1wMac';
const INQUIRY_SHEET_ID = '1pbB2kXGjWt9PU8kbW0qiNDnkQ4bpIFK45fKjZOgc87A';

function doPost(e) {
  try {
    const params = JSON.parse(e.postData.contents);
    if (params.action === 'submitCustomForm') return handleCustomFormSubmission(params);
    return createJsonResponse({ error: '未知操作' });
  } catch (err) {
    return createJsonResponse({ error: '系統錯誤', details: err.toString() });
  }
}

function handleCustomFormSubmission(data) {
  try {
    const ssId = data.formType === '點燈報名' ? LIGHTING_SHEET_ID : INQUIRY_SHEET_ID;
    const ss = SpreadsheetApp.openById(ssId);
    const sheet = ss.getSheets()[0];
    const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];

    const newRow = headers.map(header => {
      const h = header.toString().trim();

      // 修復邏輯：防止空值導致報錯
      const getValue = (val) => {
        if (!val) return ""; // 指令優化：如果值為空，直接回傳空字串
        return val;
      };

      if (h === '提交時間') return getValue(data.timestamp);
      if (h === '姓名') return getValue(data.name);
      if (h === '電話') return getValue(data.phone);
      if (h === '生日') return getValue(data.birthday);
      if (h === '性別') return getValue(data.gender);
      if (h === '地址') return getValue(data.address);
      if (h === '項目' || h === '類別') return getValue(data.item);
      if (h === '說明' || h === '事由') return getValue(data.reason);
      return "";
    });

    sheet.appendRow(newRow);
    return createJsonResponse({ success: true });
  } catch (e) {
    return createJsonResponse({ error: '寫入失敗', details: e.toString() });
  }
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
}

