@media(min-width: 768px) { .slide-content { flex-direction: row; } }
.slide img, .image-placeholder { width: 320px; height: 400px; object-fit: contain; background: #fafafa; }
.image-placeholder { display: flex; align-items: center; justify-content: center; background: #fdfbf7; }
.placeholder-circle { width: 180px; height: 180px; border: 6px solid var(--gold); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 6rem; color: var(--gold); font-weight: 900; font-family: 'Noto Serif TC', serif; }
