.quote { color: var(--gold); font-weight: 700; margin-bottom: 20px; font-size: 1.1rem; }

.slider-dots { display: flex; justify-content: center; gap: 12px; margin-top: 40px; }
.dot { width: 10px; height: 10px; border-radius: 50%; background: #ddd; cursor: pointer; transition: all 0.3s; }
.dot.active { background: var(--red); width: 35px; border-radius: 10px; }

/* Footer */
footer { background: var(--red); color: white; padding: 60px 0 20px; text-align: center; }
.logo-icon-small { border: 1.5px solid white; padding: 2px 5px; margin-right: 10px; font-weight: 900; }
.footer-info { margin: 25px 0; font-size: 14px; opacity: 0.8; }
.footer-links { display: flex; justify-content: center; gap: 25px; margin-bottom: 45px; }
.footer-links a { color: white; text-decoration: none; font-size: 12px; border: 1px solid rgba(255,255,255,0.4); padding: 8px 20px; font-weight: 700; }
.copyright { font-size: 10px; opacity: 0.4; letter-spacing: 0.3em; margin-top: 30px; }

/* Page Specific */
.page-content { padding: 180px 0 120px; }
.p-content { padding: 60px; background: white; }
.text-red { color: var(--red); margin-bottom: 25px; }
.step-card { display: flex; gap: 35px; padding: 45px; background: white; margin-bottom: 45px; align-items: flex-start; }
.step-num { width: 60px; height: 60px; background: var(--red); color: white; display: flex; align-items: center; justify-content: center; font-weight: 900; font-size: 26px; flex-shrink: 0; box-shadow: 4px 4px 0 var(--gold); }
.god-list { color: var(--red); font-weight: 900; font-size: 1.8rem; margin-bottom: 18px; border-bottom: 1px solid #eee; padding-bottom: 15px; }

@media(max-width: 768px) {
  .main-slogan { font-size: 3rem; }
  nav a:not(.logo) { display: none; }
  .mobile-only { display: block; border: none; background: none; color: var(--red); font-size: 20px; font-weight: 900; }
}

document.addEventListener('DOMContentLoaded', () => {
  // 1. Header 滾動切換
  const header = document.getElementById('main-header');
  const handleScroll = () => {
    if (window.scrollY > 50) {
      header.classList.add('scrolled');
    } else {
      header.classList.remove('scrolled');
    }
  };
  window.addEventListener('scroll', handleScroll);
  handleScroll();

  // 2. 行動版選單
  const menuToggle = document.getElementById('menu-toggle');
  const closeMenu = document.getElementById('close-menu');
  const mobileMenu = document.getElementById('mobile-menu');

  if (menuToggle) {
    menuToggle.addEventListener('click', () => {
      mobileMenu.classList.remove('hidden');
      document.body.style.overflow = 'hidden';
    });
  }
  if (closeMenu) {
    closeMenu.addEventListener('click', () => {
      mobileMenu.classList.add('hidden');
      document.body.style.overflow = '';
    });
  }

  // 3. 水平滑動條分頁點同步
  const track = document.getElementById('slider-track');
  const dotsContainer = document.getElementById('slider-dots');
  const slides = document.querySelectorAll('.slide');

  if (track && dotsContainer && slides.length > 0) {
    // 建立分頁點
    slides.forEach((_, i) => {
      const dot = document.createElement('div');
      dot.classList.add('dot');
      if (i === 0) dot.classList.add('active');
      dot.addEventListener('click', () => {
        track.scrollTo({
          left: i * track.clientWidth,
          behavior: 'smooth'
        });
      });
      dotsContainer.appendChild(dot);
    });

    // 監聽滾動更新點點樣式
    track.addEventListener('scroll', () => {
      const index = Math.round(track.scrollLeft / track.clientWidth);
      const dots = dotsContainer.querySelectorAll('.dot');
      dots.forEach((dot, i) => {
        dot.classList.toggle('active', i === index);
      });
    });
  }
});

