                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                       <div className="space-y-2">
                        <label className="text-xs font-black text-[#8B0000] uppercase tracking-widest">性別</label>
                        <select className="w-full bg-[#FDFBF7] border border-gray-100 p-4 outline-none focus:ring-1 focus:ring-[#8B0000]"
                          value={formData.gender} onChange={(e) => setFormData({...formData, gender: e.target.value})}>
                          <option value="男">男</option>
                          <option value="女">女</option>
                        </select>
                      </div>
                      <div className="space-y-2">
