    <div className={`bg-white ornament-border ${isMain ? 'p-8 md:p-12' : 'p-6 md:p-8'} shadow-xl border-l-4 border-[#B22222] flex flex-col group transition-all duration-500 hover:-translate-y-1 h-full`}>
