              {act.label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen text-[#333333] overflow-x-hidden bg-white">
      <Header 
        onHomeClick={() => setCurrentView('Home')}
