                  {/* 第二排：祈福燈 & 問事 (並排) */}
                  <div className="md:col-span-1">
                    <NewsCard news={LATEST_NEWS[1]} />
                  </div>
                  <div className="md:col-span-1">
                    <NewsCard news={LATEST_NEWS[2]} />
                  </div>
                </div>
